const CHAT_API_URL = 'https://api.rbrowser.org/api/v1/chat/'
const GET_TRANSCRIPTS_API_URL = 'https://api.rbrowser.org/api/v1/get-transcripts/'

type TranscriptItem = {
  trans_id: string
  trans_name: string
  trans_type?: string
  gene_id?: string
  gene_name?: string
  action?: string
}

type TranscriptGroup = {
  key: string
  label: string
  items: TranscriptItem[]
  sortKey: string
}

/** 按 gene_name 分组 */
function buildTranscriptGroups(transcripts: TranscriptItem[]): TranscriptGroup[] {
  if (!transcripts || transcripts.length === 0) return []

  // 过滤空名称
  const validTranscripts = transcripts.filter((t) => t.trans_name && t.trans_name.trim())

  const byGene = new Map<string, TranscriptItem[]>()
  for (const t of validTranscripts) {
    const key = t.gene_name || 'Unknown'
    if (!byGene.has(key)) byGene.set(key, [])
    byGene.get(key)!.push(t)
  }

  const groups: TranscriptGroup[] = []
  for (const [key, items] of byGene) {
    items.sort((a, b) => (a.trans_name || '').localeCompare(b.trans_name || '', 'en'))
    groups.push({ key, label: key, items, sortKey: key.toLowerCase() })
  }

  groups.sort((a, b) => a.sortKey.localeCompare(b.sortKey))
  return groups
}

/**
 * 获取基因的转录本信息
 */
const getTranscripts = async (genes: any[], transcriptome = 'hg38') => {
  try {
    const response = await fetch(GET_TRANSCRIPTS_API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        genes: genes,
        transcriptome: transcriptome
      })
    })

    const data = await response.json()
    if (data.status === 1 && data.results && data.results.transcripts) {
      return data.results.transcripts
    }
    return [] // 如果查询失败，返回空数组
  } catch (error) {
    console.error('Get transcripts error:', error)
    return [] // 如果查询失败，返回空数组
  }
}

const Chat: FC<Iprops> = () => {
  const dispatch = useAppDispatch()
  const [open, setOpen] = useState(false)

  const chat_cpn = (
    <>
      <Typography level='body-sm' sx={{ color: 'text.primary', fontWeight: '500' }}>
        Welcome to RBrowser!
      </Typography>
      <br />
      <Typography level='body-sm' sx={{ color: 'text.primary' }}>
        RBrowser GPT is a personal assistant for answering questions about the RBrowser and RNA knowledge.
      </Typography>
      <Typography level='body-sm' sx={{ color: 'text.primary' }}>
        Note: AI-generated content may contain inaccuracies.
      </Typography>
      <Typography level='body-sm' sx={{ color: 'text.primary' }}>
        You can start a conversation here or try the following:
      </Typography>
      <Box sx={{ mt: 1 }}>
        <Stack spacing={1} alignItems='flex-start'>
          <Button
            variant='outlined'
            size='sm'
            onClick={() => setInput('I want to check the transcript of MOV10.')}
            sx={{ textTransform: 'none', marginRight: 1, fontSize: '13px' }}>
            I want to check the transcript of MOV10.
          </Button>
          <Button
            variant='outlined'
            size='sm'
            onClick={() => setInput('What are the m6A RNA modification readers?')}
            sx={{ textTransform: 'none', marginRight: 1, fontSize: '13px' }}>
            What are the m6A RNA modification readers?
          </Button>
          <Button
            variant='outlined'
            size='sm'
            onClick={() => setInput('Is there single-base RNA modification data here?')}
            sx={{ textTransform: 'none', fontSize: '13px' }}>
            Is there single-base RNA modification data here?
          </Button>
        </Stack>
      </Box>
    </>
  )

  const [messages, setMessages] = useState<{ sender: string; text: ReactNode }[]>([
    {
      sender: 'machine',
      text: chat_cpn
    }
  ])
  const [input, setInput] = useState('')
  const [isTyping, setIsTyping] = useState(false)
  const messagesEndRef = useRef<HTMLDivElement | null>(null)
  const abortControllerRef = useRef<AbortController | null>(null)
  const messagesContainerRef = useRef<HTMLDivElement | null>(null)
  const [userScrolled, setUserScrolled] = useState(false)

  const scrollToBottom = () => {
    if (!userScrolled) {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
    }
  }

  useEffect(() => {
    scrollToBottom()
  }, [messages, userScrolled])

  // 当打开对话框时，滚动到底部
  useEffect(() => {
    if (open) {
      setUserScrolled(false)
      // 延迟滚动以确保 DOM 已渲染
      setTimeout(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
      }, 100)
    }
  }, [open])

  // 检测用户是否手动滚动
  const handleScroll = () => {
    const container = messagesContainerRef.current
    if (container) {
      const { scrollTop, scrollHeight, clientHeight } = container
      // 如果不在底部，说明用户向上滚动了
      const isAtBottom = scrollHeight - scrollTop - clientHeight < 50 // 50px 容错
      if (!isAtBottom) {
        setUserScrolled(true)
      } else {
        // 如果滚动回底部，恢复自动跟随
        setUserScrolled(false)
      }
    }
  }

  const handleSend = async () => {
    if (!input.trim()) return

    setMessages((prev) => [...prev, { sender: 'user', text: input }])
    setInput('')
    setUserScrolled(false) // 重置滚动状态

    const thinkingElement = (
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
        <SyncOutlined spin style={{ fontSize: '14px', color: '#1976d2' }} />
        <Typography level='body-xs' sx={{ fontSize: '13px', color: 'text.primary' }}>
          Thinking
        </Typography>
      </Box>
    )
    const loadingMessage = { sender: 'machine', text: thinkingElement }
    setMessages((prev) => [...prev, loadingMessage])
    setIsTyping(true)

    // 创建新的 AbortController
    abortControllerRef.current = new AbortController()

    try {
      const response = await fetch(CHAT_API_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          message: input
        }),
        signal: abortControllerRef.current.signal
      })

      const reader = response.body?.getReader()
      const decoder = new TextDecoder()
      let done = false

      let accumulatedText = ''
      let jsonData = ''
      let parsedTable = []
      let isLoadingShown = false
      setMessages((prev) => prev.filter((msg) => msg.text !== thinkingElement))

      while (!done) {
        // 检查是否已中断
        if (abortControllerRef.current?.signal.aborted) {
          break
        }

        const { value, done: readerDone } = (await reader?.read()) || {}
        done = readerDone as boolean
        console.log('Received chunk:', readerDone)
        if (value) {
          const chunk = decoder.decode(value, { stream: true })
          const jsonStrings = chunk.split(/data: /).filter((str) => str.trim() !== '')

          jsonStrings.forEach((jsonString) => {
            try {
              // 跳过 [DONE] 标记
              if (jsonString.trim() === '[DONE]') return

              const parsed = JSON.parse(jsonString)
              const deltaContent = parsed?.choices?.[0]?.delta?.content

              console.log('Received chunk:', deltaContent)
              if (deltaContent) {
                accumulatedText += deltaContent

                // Extract JSON table if present
                const jsonStartIndex = accumulatedText.indexOf('>>>')
                const jsonStart = jsonStartIndex + 3
                const jsonEndIndex = accumulatedText.lastIndexOf('<<<')

                // 检测到 >>> 但未检测到 <<<，显示 Loading（只显示一次）
                if (jsonStartIndex !== -1 && jsonEndIndex === -1 && !isLoadingShown) {
                  isLoadingShown = true
                  setMessages((prev) => {
                    const updated = [...prev]
                    const beforeText = accumulatedText.slice(0, jsonStartIndex).trim()
                    updated[updated.length - 1] = {
                      sender: 'machine',
                      text: (
                        <Box>
                          {beforeText && <MarkdownContent content={beforeText} />}
                          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mt: 1 }}>
                            <SyncOutlined spin style={{ fontSize: '14px', color: '#1976d2' }} />
                            <Typography level='body-xs' sx={{ fontSize: '13px', color: 'text.primary' }}>
                              Thinking
                            </Typography>
                          </Box>
                        </Box>
                      )
                    }
                    return updated
                  })
                }

                // 检测到完整的 >>> ... <<<
                if (jsonStartIndex !== -1 && jsonEndIndex !== -1) {
                  jsonData = accumulatedText.slice(jsonStart, jsonEndIndex).trim()
                  parsedTable = JSON.parse(jsonData)

                  // 获取转录本信息
                  getTranscripts(parsedTable, 'hg38').then((transcripts) => {
                    const groups = buildTranscriptGroups(transcripts)

                    // 创建一个带 Search 的 List 组件
                    const TranscriptList: React.FC = () => {
                      const [search, setSearch] = React.useState('')
                      const [expanded, setExpanded] = React.useState<Set<string>>(new Set(groups.map((g) => g.key)))

                      const filteredGroups = React.useMemo(() => {
                        if (!search.trim()) return groups
                        const searchLower = search.toLowerCase()
                        return groups
                          .map((g) => ({
                            ...g,
                            items: g.items.filter(
                              (item) =>
                                item.trans_name?.toLowerCase().includes(searchLower) ||
                                item.trans_id?.toLowerCase().includes(searchLower)
                            )
                          }))
                          .filter((g) => g.items.length > 0)
                      }, [search])

                      const toggleGroup = (key: string) => {
                        setExpanded((prev) => {
                          const next = new Set(prev)
                          if (next.has(key)) next.delete(key)
                          else next.add(key)
                          return next
                        })
                      }

                      return (
                        <Box sx={{ mt: 1 }}>
                          {/* Search 输入框 */}
                          <Input
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            placeholder='Search transcripts...'
                            size='sm'
                            startDecorator={<SearchIcon sx={{ fontSize: '16px' }} />}
                            endDecorator={
                              search ? (
                                <IconButton size='sm' onClick={() => setSearch('')} sx={{ p: 0.25 }}>
                                  <CloseIcon sx={{ fontSize: '16px' }} />
                                </IconButton>
                              ) : null
                            }
                            sx={{ mb: 0.5, fontSize: '13px', color: 'text.primary' }}
                            slotProps={{
                              input: {
                                sx: { fontSize: '13px', color: 'text.primary' }
                              }
                            }}
                          />

                          {/* 分组列表 */}
                          <List
                            dense
                            disablePadding
                            sx={{
                              maxHeight: '200px',
                              overflowY: 'auto',
                              border: '1px solid',
                              borderColor: 'divider',
                              borderRadius: '4px'
                            }}>
                            {filteredGroups.map((g) => {
                              const isOpen = expanded.has(g.key)
                              return (
                                <React.Fragment key={g.key}>
                                  {/* 分组标题 */}
                                  <Box
                                    sx={{
                                      px: 1,
                                      py: 0.25,
                                      display: 'flex',
                                      alignItems: 'center',
                                      gap: 0.25,
                                      bgcolor: 'background.level1'
                                    }}>
                                    <IconButton2
                                      size='small'
                                      onClick={() => toggleGroup(g.key)}
                                      sx={{ mr: 0.25, p: 0.25 }}>
                                      {isOpen ? (
                                        <ExpandMoreIcon fontSize='small' />
                                      ) : (
                                        <KeyboardArrowRightIcon fontSize='small' />
                                      )}
                                    </IconButton2>

                                    <Tooltip title={g.label} arrow enterDelay={550} placement='top'>
                                      <Typography
                                        noWrap
                                        sx={{
                                          px: 0.5,
                                          py: 0.5,
                                          fontSize: '13px',
                                          color: 'text.secondary',
                                          textTransform: 'uppercase',
                                          letterSpacing: 0.3,
                                          userSelect: 'none',
                                          flex: 1,
                                          overflow: 'hidden',
                                          textOverflow: 'ellipsis'
                                        }}>
                                        {g.label}
                                      </Typography>
                                    </Tooltip>

                                    <Typography
                                      component='span'
                                      sx={{
                                        fontSize: 11,
                                        color: 'neutral.600',
                                        fontWeight: 500,
                                        minWidth: 24,
                                        textAlign: 'right',
                                        ml: 0.5,
                                        flex: '0 0 auto'
                                      }}>
                                      {g.items.length}
                                    </Typography>
                                  </Box>

                                  {/* 组内容 */}
                                  {isOpen &&
                                    g.items.map((item, i) => (
                                      <ListItemButton
                                        key={item.trans_id ?? i}
                                        dense
                                        onClick={() =>
                                          handleTranscriptClick(
                                            item.trans_id,
                                            item.trans_name,
                                            item.trans_type || 'other',
                                            item.gene_id || '',
                                            item.gene_name || '',
                                            item.action || ''
                                          )
                                        }
                                        sx={{ pr: '5px', gap: 0, alignItems: 'center' }}>
                                        <TransTypeBadge transType={item.trans_type} size={18} />
                                        <ListItemText
                                          primary={item.trans_name}
                                          secondary={item.trans_id}
                                          primaryTypographyProps={{ fontSize: 12 }}
                                          secondaryTypographyProps={{ fontSize: 7, color: 'text.disabled' }}
                                          sx={{
                                            pl: '5px',
                                            m: 0,
                                            whiteSpace: 'nowrap',
                                            overflow: 'hidden',
                                            textOverflow: 'ellipsis'
                                          }}
                                        />
                                      </ListItemButton>
                                    ))}

                                  <Divider sx={{ my: 0.25 }} />
                                </React.Fragment>
                              )
                            })}
                          </List>
                        </Box>
                      )
                    }

                    setMessages((prev) => {
                      const updated = [...prev]
                      const beforeText = accumulatedText.slice(0, jsonStartIndex).trim()
                      const afterText = accumulatedText.slice(jsonEndIndex + 3).trim()
                      updated[updated.length - 1] = {
                        sender: 'machine',
                        text: (
                          <Box>
                            {beforeText && <MarkdownContent content={beforeText} />}
                            <TranscriptList />
                            {afterText && (
                              <Box sx={{ mt: 1 }}>
                                <MarkdownContent content={afterText} />
                              </Box>
                            )}
                          </Box>
                        )
                      }
                      return updated
                    })
                  })
                } else if (!isLoadingShown) {
                  // 正常显示流式文本（只要没有显示 Loading）
                  setMessages((prev) => {
                    const updated = [...prev]
                    const lastMessage = updated[updated.length - 1]
                    if (lastMessage && lastMessage.sender === 'machine') {
                      lastMessage.text = <MarkdownContent content={accumulatedText} />
                    } else {
                      updated.push({
                        sender: 'machine',
                        text: <MarkdownContent content={accumulatedText} />
                      })
                    }
                    return updated
                  })
                }
              }
            } catch (e) {
              console.error('Error parsing chunk:', e)
            }
          })
        }
      }

      setIsTyping(false)
    } catch (error: any) {
      if (error.name === 'AbortError') {
        // 用户取消了请求
        setMessages((prev) => prev.filter((msg) => msg.text !== thinkingElement))
      } else {
        setMessages((prev) => [
          ...prev.filter((msg) => msg.text !== thinkingElement),
          {
            sender: 'machine',
            text: (
              <Typography level='body-sm' sx={{ fontSize: '13px' }}>
                Error: Unable to fetch response.
              </Typography>
            )
          }
        ])
      }
      setIsTyping(false)
    }
  }

  const handleStop = () => {
    console.log('Stopping the response...')
    if (abortControllerRef.current) {
      abortControllerRef.current.abort()
      abortControllerRef.current = null
    }
    setIsTyping(false)
  }

  const handleTranscriptClick = (
    transId: string,
    transName: string,
    transType: string,
    geneId: string,
    geneName: string,
    action: string
  ) => {
    try {
      // TODO: 使用 geneId 和 geneName
      console.log(`Clicked transcript: ${transId} (${transName}), gene: ${geneId} (${geneName}), action: ${action}`)

      const _target: IRBRegion = {
        id: nanoid(),
        time: new Date().getTime(),
        chr: '',
        start: 0,
        end: 0,
        strand: '+',
        offset: 5000,
        gene_id: geneId || '',
        trans_id: transId,
        trans_name: transName,
        trans_type: transType ?? 'other',
        level: 'RNA'
      }

      dispatch(setCurrentRegion(_target))
      dispatch(setHistoryRegion(_target))

      updateLocalStorage('currentRNA', transName)
      updateLocalStorage('currentTransID', transId)
      updateLocalStorage('currentProtein', transName.split('-')[0].toUpperCase())

      message.success(`Switched to transcript: ${transName}`)
    } catch (error) {
      console.error('Error switching transcript:', error)
      message.error('Failed to switch transcript')
    }
  }

  const handleClear = () => {
    setMessages([
      {
        sender: 'machine',
        text: chat_cpn
      }
    ])
  }

  return (
    <>
      <Box
        id='chat-fab-btn'
        sx={{
          position: 'fixed',
          bottom: '30px',
          right: '45px',
          zIndex: 1000
        }}>
        <IconButton
          variant='solid'
          onClick={() => setOpen((prev) => !prev)}
          sx={{
            borderRadius: '50%',
            width: '56px',
            height: '56px',
            minWidth: 'unset',
            fontSize: '24px',
            background: 'linear-gradient(135deg, #6b64f8, #3158e9)',
            boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
            backdropFilter: 'blur(10px)',
            WebkitBackdropFilter: 'blur(10px)',
            color: '#fff',
            border: '1px solid rgba(255, 255, 255, 0.3)',
            transition: 'transform 0.2s ease',
            '&:hover': {
              transform: 'scale(1.1)',
              boxShadow: '0 6px 8px rgba(0, 0, 0, 0.2)'
            }
          }}>
          <SmartToyRounded />
        </IconButton>
      </Box>

      {open && (
        <Box
          sx={{
            position: 'fixed',
            bottom: '80px',
            right: '46px',
            width: '600px',
            height: '450px',
            bgcolor: 'background.surface',
            boxShadow: 'lg',
            borderRadius: 'md',
            overflow: 'hidden',
            display: 'flex',
            flexDirection: 'column',
            zIndex: 999999,
            border: '1px solid #33383e'
          }}>
          <Box
            sx={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              borderBottom: '1px solid',
              borderColor: 'divider',
              bgcolor: '#eef2fa'
            }}>
            <Typography sx={{ color: '#32383E', paddingLeft: '15px', fontSize: '16px' }}>
              RBrowser GPT<Typography sx={{ color: '#32383E', paddingLeft: '5px', fontSize: '13px' }}>Beta</Typography>
            </Typography>
            <Stack spacing={1} direction='row'>
              <Button
                sx={{ color: '#32383E', fontWeight: '500' }}
                size='sm'
                variant='plain'
                onClick={handleClear}
                startDecorator={<Brush sx={{ fontSize: '16px' }} />}>
                Clear
              </Button>
              <IconButton
                onClick={() => setOpen(false)}
                sx={{
                  fontSize: '20px'
                }}>
                <Close />
              </IconButton>
            </Stack>
          </Box>

          <Box
            ref={messagesContainerRef}
            onScroll={handleScroll}
            sx={{
              flex: 1,
              p: 2,
              overflowY: 'auto',
              display: 'flex',
              flexDirection: 'column',
              gap: 2
            }}>
            {messages.map((msg, index) => (
              <Box
                key={index}
                sx={{
                  display: 'flex',
                  flexDirection: msg.sender === 'user' ? 'row-reverse' : 'row',
                  alignItems: 'flex-start',
                  gap: 1
                }}>
                {msg.sender === 'user' ? (
                  <Avatar
                    sx={{
                      width: 40,
                      height: 40,
                      bgcolor: 'white',
                      border: '1px solid #d3d3d3'
                    }}></Avatar>
                ) : (
                  <Avatar
                    sx={{
                      width: 40,
                      height: 40,
                      bgcolor: 'white',
                      border: '1px solid #d3d3d3'
                    }}>
                    <SmartToyOutlined />
                  </Avatar>
                )}
                <Box
                  sx={{
                    maxWidth: '90%',
                    p: 1.5,
                    borderRadius: '12px',
                    bgcolor: '#eef2fa',
                    border: '1px solid #d5e3fe'
                  }}>
                  <Box sx={{ fontSize: '13px', color: '#32383E' }}>{msg.text}</Box>
                </Box>
              </Box>
            ))}
            <div ref={messagesEndRef} />
          </Box>

          <Box
            sx={{
              p: 1,
              display: 'flex',
              gap: 1,
              borderTop: '1px solid',
              borderColor: 'divider'
            }}>
            <Input
              placeholder='Chat with RBrowser'
              sx={{ '--Input-decoratorChildHeight': '32px', fontSize: '13px', color: '#32383E' }}
              fullWidth
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && !isTyping && handleSend()}
              readOnly={isTyping}
              slotProps={{
                input: {
                  sx: { fontSize: '13px', color: '#32383E' }
                }
              }}
              endDecorator={
                <IconButton
                  aria-label={isTyping ? 'Stop' : 'Send'}
                  size='sm'
                  onClick={isTyping ? handleStop : handleSend}>
                  {isTyping ? <Stop sx={{ fontSize: '18px' }} /> : <NorthRounded sx={{ fontSize: '18px' }} />}
                </IconButton>
              }
            />
          </Box>
        </Box>
      )}
    </>
  )
}

export default memo(Chat)
