import React, { memo, useEffect, useMemo, useRef, useState } from 'react'
import type { FC, ReactNode } from 'react'
import AsideMenu from '@/views/main/c-cpns/left-asider/c-cpns/index'
import { MainHomeWraaper } from './style'
import { getTranscriptList } from '@/service/modules/transcript'
import { setCurrentRegion, setHistoryRegion, IRBRegion } from '@/store/modules/rna_browser_settings'
import { useAppDispatch } from '@/store'
import { nanoid } from 'nanoid'
import { historyManager } from '@rbrowser/main'

import { Box, Typography, Input, CircularProgress } from '@mui/joy'
import List from '@mui/material/List'
import ListItemButton from '@mui/material/ListItemButton'
import ListItemText from '@mui/material/ListItemText'
import Divider from '@mui/material/Divider'
import Tooltip from '@mui/material/Tooltip'
import IconButton from '@mui/material/IconButton'
import ExpandMoreIcon from '@mui/icons-material/ExpandMore'
import KeyboardArrowRightIcon from '@mui/icons-material/KeyboardArrowRight'
import SearchIcon from '@mui/icons-material/Search'
import CloseIcon from '@mui/icons-material/Close'
import { TRANS_TYPE_META } from '@/constants/transType'
import BMLoding from '@/components/loading'

interface Iprops {
  children?: ReactNode
}

type TransItem = {
  trans_id: string
  trans_name: string
  trans_type?: string
  [k: string]: any
}

type Group = {
  key: string // trans_type
  label: string // 显示名
  items: TransItem[]
  sortKey: string
}

const formatTitle = (str: string) => (str || '').replace(/_/g, ' ').replace(/(^|\s)[a-z]/g, (m) => m.toUpperCase())

/** TransType 徽标 */
const TransTypeBadge: React.FC<{ transType?: string; size?: number }> = ({ transType, size = 18 }) => {
  const key = transType ?? ''
  const meta = TRANS_TYPE_META[key] ?? { color: '#9e9e9e', label: 'OT' }
  const fullName = (transType && transType.replace(/_/g, ' ')) || 'other'
  return (
    <Tooltip title={fullName} arrow enterDelay={250} placement='right'>
      <Box
        component='span'
        role='img'
        aria-label={fullName}
        sx={{
          width: size,
          height: size,
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          borderRadius: '3px',
          backgroundColor: meta.color,
          color: '#fff',
          fontSize: size <= 18 ? 10 : 11,
          fontWeight: 700,
          lineHeight: 1,
          flex: '0 0 auto',
          userSelect: 'none',
          mr: 0.75
        }}>
        {meta.label}
      </Box>
    </Tooltip>
  )
}

/** 基础分组：按 trans_type -> items[]；组内按 trans_name 升序；分组按 label 升序 */
function buildGroups(rows: TransItem[] | undefined): Group[] {
  if (!rows || rows.length === 0) return []
  const byType = new Map<string, TransItem[]>()
  for (const r of rows) {
    const key = r.trans_type ?? 'other'
    if (!byType.has(key)) byType.set(key, [])
    byType.get(key)!.push(r)
  }
  const groups: Group[] = []
  for (const [key, items] of byType) {
    items.sort((a, b) => (a.trans_name || '').localeCompare(b.trans_name || '', 'en'))
    const label = formatTitle(key)
    groups.push({ key, label, items, sortKey: label.toLowerCase() })
  }
  groups.sort((a, b) => a.sortKey.localeCompare(b.sortKey))
  return groups
}

const Home: FC<Iprops> = () => {
  const dispatch = useAppDispatch()

  /** 搜索框 & 数据 */
  const [search, setSearch] = useState('vamp3')
  const [loading, setLoading] = useState(false)
  const [rows, setRows] = useState<TransItem[]>([])
  const [errorTip, setErrorTip] = useState<string | null>(null)
  const [isInit, setIsInit] = useState(true)

  /** 自适应高度 */
  const [maxHeight, setMaxHeight] = useState<number>(window.innerHeight - 85)
  useEffect(() => {
    const onResize = () => setMaxHeight(window.innerHeight - 85)
    window.addEventListener('resize', onResize)
    return () => window.removeEventListener('resize', onResize)
  }, [])

  /** 去抖搜索 */
  const [debounced, setDebounced] = useState(search)
  useEffect(() => {
    const t = setTimeout(() => setDebounced(search.trim()), 180)
    return () => clearTimeout(t)
  }, [search])

  /** 发请求（带竞态序号） */
  const seqRef = useRef(0)
  useEffect(() => {
    let alive = true
    const mySeq = ++seqRef.current

    if (debounced === '') {
      if (alive && mySeq === seqRef.current) {
        setIsInit(true)
        setErrorTip(null)
        setRows([])
      }
      return
    }

    setLoading(true)
    setIsInit(false)
    setErrorTip(null)
    ;(async () => {
      try {
        const res: any = await getTranscriptList({ search: debounced, transcriptome: 'hg38' })
        if (!alive || mySeq !== seqRef.current) return
        console.log('getTranscriptList', res.message)

        if ('data' in res) {
          const list = (res.data?.results ?? []) as TransItem[]
          setRows(list)
        } else {
          setRows([])
          // if status code 400/500
          setErrorTip(res.message)
        }
      } catch (_) {
        if (alive && mySeq === seqRef.current) {
          setRows([])
          setErrorTip('Please check your input')
        }
      } finally {
        if (alive && mySeq === seqRef.current) setLoading(false)
      }
    })()

    return () => {
      alive = false
    }
  }, [debounced])

  /** 基础分组 */
  const groupsBase = useMemo(() => buildGroups(rows), [rows])

  /** 按规则生成“展示分组顺序”和“默认展开集”：
   * - 多分组：无论总数多少，都把 protein_coding 置顶
   * - 展开规则：单分组=只展开；多分组&>20=仅展开 protein_coding（或第一个）；多分组&≤20=全部展开
   */
  const { groupsDisplay, defaultExpanded } = useMemo(() => {
    if (groupsBase.length === 0) return { groupsDisplay: [] as Group[], defaultExpanded: new Set<string>() }

    const totalItems = groupsBase.reduce((acc, g) => acc + g.items.length, 0)
    const onlyOneGroup = groupsBase.length === 1

    // 先得到基础顺序，再做置顶处理
    let ordered = [...groupsBase]
    if (!onlyOneGroup) {
      const idxPC = ordered.findIndex((g) => g.key === 'protein_coding')
      if (idxPC > -1) {
        const [pc] = ordered.splice(idxPC, 1)
        ordered = [pc, ...ordered]
      }
    }

    if (onlyOneGroup) {
      return { groupsDisplay: ordered, defaultExpanded: new Set([ordered[0].key]) }
    }

    if (totalItems > 20) {
      // 多分组且条目 > 20：仅展开 protein_coding（若不存在则只展开第一个）
      const hasPC = ordered[0]?.key === 'protein_coding' || ordered.some((g) => g.key === 'protein_coding')
      if (hasPC) return { groupsDisplay: ordered, defaultExpanded: new Set(['protein_coding']) }
      return { groupsDisplay: ordered, defaultExpanded: new Set([ordered[0].key]) }
    }

    // 多分组且条目 ≤ 20：全部展开（protein_coding 已置顶）
    return { groupsDisplay: ordered, defaultExpanded: new Set(ordered.map((g) => g.key)) }
  }, [groupsBase])

  /** 展开状态：每次分组变化都按规则重置 */
  const [expanded, setExpanded] = useState<Set<string>>(defaultExpanded)
  useEffect(() => {
    setExpanded(defaultExpanded)
  }, [defaultExpanded])

  const toggleGroup = (key: string) => {
    setExpanded((prev) => {
      const next = new Set(prev)
      if (next.has(key)) next.delete(key)
      else next.add(key)
      return next
    })
  }

  /** 点击条目：使用你给的实现 */
  const handleClickItem = (item: TransItem) => {
    const _target: IRBRegion = {
      id: nanoid(),
      time: new Date().getTime(),
      chr: '',
      start: 0,
      end: 0,
      strand: '+',
      offset: 5000,
      gene_id: '',
      trans_id: item.trans_id,
      trans_name: item.trans_name,
      trans_type: item.trans_type ?? 'other',
      level: 'RNA'
    }

    dispatch(setCurrentRegion(_target))
    dispatch(setHistoryRegion(_target))

    // 🆕 记录到 historyManager（包的内置 History 管理）
    // 格式: trans_name:offset:trans_type（trans_type 用于 History 面板颜色标识）
    const transType = item.trans_type ?? 'other'
    if (item.trans_name) {
      historyManager.add(`${item.trans_name}:5000:${transType}`)
    } else if (item.trans_id) {
      historyManager.add(`${item.trans_id}:5000:${transType}`)
    }

    // localStorage 同步由 transcript view 的 setNavigationChangeCallback 统一处理
    // dispatch(setCurrentRegion) → 触发 renderer 导航 → 回调自动同步所有 localStorage keys
  }

  return (
    <MainHomeWraaper>
      <AsideMenu name='Search' />

      <div className='content' style={{ height: maxHeight, flex: 1, overflowY: 'auto', position: 'relative' }}>
        {/* 顶部搜索（吸顶） */}
        <Box
          sx={{
            position: 'sticky',
            top: 0,
            zIndex: 3,
            bgcolor: 'background.body',
            borderBottom: '1px solid',
            borderColor: 'divider',
            p: '3px 8px',
            height: 38,
            display: 'flex',
            alignItems: 'center',
            boxShadow: 'none'
          }}>
          <Input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder='Search transcripts (name, ENST…, gene)…'
            size='sm'
            startDecorator={<SearchIcon fontSize='small' />}
            sx={{
              flex: 1,
              p: '3px',
              '--Input-focusedThickness': '0px',
              '--variant-borderWidth': '0px',
              border: 'none',
              boxShadow: 'none',
              backgroundColor: 'transparent',
              '&::before': { display: 'none' }
            }}
            endDecorator={
              search ? (
                <IconButton size='small' onClick={() => setSearch('')} sx={{ p: 0.25 }}>
                  <CloseIcon fontSize='small' />
                </IconButton>
              ) : null
            }
            slotProps={{ input: { 'aria-label': 'Search transcripts' } }}
          />
        </Box>

        {/* Loading 遮罩 */}
        <BMLoding show={loading} />

        {/* 初始提示 / 错误提示 */}
        {isInit && rows.length === 0 && (
          <Typography sx={{ textAlign: 'center', m: '10px 0', color: '#707070', fontSize: 14 }}>
            Enter a transcript query
            <br />
            (e.g., VAMP3-201, ENST00000487194, TP53)
          </Typography>
        )}
        {errorTip && !loading && (
          <Typography sx={{ textAlign: 'center', m: '10px 0', color: '#ff0000', fontSize: '14px' }}>
            {errorTip}
          </Typography>
        )}

        {/* 分组列表 */}
        {!loading && groupsDisplay.length > 0 && (
          <List dense disablePadding>
            {groupsDisplay.map((g) => {
              const isOpen = expanded.has(g.key)
              return (
                <React.Fragment key={g.key}>
                  {/* 组标题 */}
                  {/* 分组标题（带折叠、右侧计数、单行省略 + tooltip） */}
                  <Box sx={{ px: 1, py: 0.25, display: 'flex', alignItems: 'center', gap: 0.25 }}>
                    <IconButton
                      size='small'
                      onClick={() => toggleGroup(g.key ?? g.label)}
                      sx={{ mr: 0.25, p: 0.25 }}
                      aria-label={(expanded.has(g.key ?? g.label) ? 'Collapse ' : 'Expand ') + (g.label || g.key)}>
                      {expanded.has(g.key ?? g.label) ? (
                        <ExpandMoreIcon fontSize='small' />
                      ) : (
                        <KeyboardArrowRightIcon fontSize='small' />
                      )}
                    </IconButton>

                    {/* Label：单行省略 + 悬浮显示完整内容；占满中间，让数字被顶到最右侧 */}
                    <Tooltip title={g.label} arrow enterDelay={550} placement='top'>
                      <Typography
                        noWrap
                        sx={{
                          px: 0.5,
                          py: 0.5,
                          fontSize: 12,
                          color: 'neutral.500',
                          textTransform: 'uppercase',
                          letterSpacing: 0.3,
                          userSelect: 'none',
                          flex: 1, // 关键：占满剩余空间，把计数推到右边
                          overflow: 'hidden',
                          textOverflow: 'ellipsis'
                        }}>
                        {g.label}
                      </Typography>
                    </Tooltip>

                    {/* 右侧计数：右对齐 */}
                    <Typography
                      component='span'
                      sx={{
                        fontSize: 12,
                        color: 'neutral.500',
                        fontWeight: 500,
                        minWidth: 24, // 给个最小宽度，避免抖动
                        textAlign: 'right', // 右对齐
                        ml: 0.5,
                        flex: '0 0 auto'
                      }}>
                      {g.items.length}
                    </Typography>
                  </Box>

                  {/* 组内容 */}
                  {isOpen &&
                    g.items.map((it, i) => {
                      const name = it.trans_name || it.trans_id || `Item ${i + 1}`
                      const key = it.trans_id ?? `${name}-${i}`
                      return (
                        <ListItemButton
                          key={key}
                          dense
                          onClick={() => handleClickItem(it)}
                          sx={{ pr: '5px', gap: 0, alignItems: 'center' }}>
                          <TransTypeBadge transType={it.trans_type} />
                          <ListItemText
                            primary={name}
                            secondary={it.trans_id}
                            primaryTypographyProps={{ fontSize: 12 }}
                            secondaryTypographyProps={{ fontSize: 7, color: 'text.disabled' }}
                            sx={{
                              pl: '5px',
                              m: 0,
                              whiteSpace: 'nowrap',
                              overflow: 'hidden',
                              textOverflow: 'ellipsis'
                            }}
                          />
                        </ListItemButton>
                      )
                    })}
                  <Divider sx={{ my: 0.5 }} />
                </React.Fragment>
              )
            })}
          </List>
        )}

        {/* 无结果 */}
        {!loading && !isInit && groupsDisplay.length === 0 && !errorTip && (
          <Typography sx={{ textAlign: 'center', m: '10px 0', color: '#707070', fontSize: 14 }}>
            No records <br /> Try another keyword.
          </Typography>
        )}
      </div>
    </MainHomeWraaper>
  )
}

export default memo(Home)
