import React, { memo, useEffect, useState, useRef, useMemo } from 'react'
import type { FC, ReactNode } from 'react'
import AsideMenu from '@/views/main/c-cpns/left-asider/c-cpns/index'
import Modal from '@mui/joy/Modal'
import ModalDialog from '@mui/joy/ModalDialog'
import { DataHubLeftSideWraaper } from './style'

import FolderOpenRounded from '@mui/icons-material/FolderOpenRounded'
import Box from '@mui/joy/Box'
import BaimoButton from '@/components/button'
import TrackList from '@/views/main/c-cpns/left-asider/track/c-cpns/track-list'
import { useRenderer } from '@/store/renderer-ref'

interface Iprops {
  children?: ReactNode
}

const DataHub: FC<Iprops> = () => {
  const isApplication = import.meta.env.VITE_IS_APPLICATION === 'true'
  const [showType, setShowType] = useState<'new' | 'modal' | 'newTab'>(isApplication ? 'newTab' : 'new')
  const [modalOpen, setModalOpen] = useState(false)

  const renderer = useRenderer() as any
  const [channels, setChannels] = useState<any[]>([])
  const unsubRef = useRef<(() => void) | null>(null)
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null)
  const prevJsonRef = useRef<string>('')

  /** 轮询间隔 ms — 作为 channelManager 事件的兜底 */
  const POLL_INTERVAL = 800

  /** 从 channelManager.getAll() 读取最新列表，仅在数据真正变化时 setState */
  const syncFromManager = React.useCallback(() => {
    if (!renderer?.channelManager) return
    try {
      const all = renderer.channelManager.getAll?.() ?? []
      const json = JSON.stringify(all)
      if (json !== prevJsonRef.current) {
        prevJsonRef.current = json
        setChannels([...all])
      }
    } catch {
      /* ignore */
    }
  }, [renderer])

  // Subscribe to channelManager + polling for robust real-time updates
  useEffect(() => {
    // Clean up previous subscription & poll
    unsubRef.current?.()
    unsubRef.current = null
    if (pollRef.current) {
      clearInterval(pollRef.current)
      pollRef.current = null
    }

    if (!renderer?.channelManager) {
      setChannels([])
      prevJsonRef.current = ''
      return
    }

    // 1) 初始同步
    syncFromManager()
    console.log('[DataHub Sidebar] Subscribed to channelManager + polling')

    // 2) 事件驱动
    try {
      unsubRef.current = renderer.channelManager.on((event: string, _detail: any) => {
        console.log(`[DataHub Sidebar] channelManager event: ${event}`)
        syncFromManager()
      })
    } catch (e) {
      console.warn('[DataHub Sidebar] channelManager.on() failed:', e)
    }

    // 3) 轮询兜底
    pollRef.current = setInterval(syncFromManager, POLL_INTERVAL)

    return () => {
      unsubRef.current?.()
      unsubRef.current = null
      if (pollRef.current) {
        clearInterval(pollRef.current)
        pollRef.current = null
      }
    }
  }, [renderer, syncFromManager])

  // Filter to only DataHub tracks (prefixed with 'RDH: ')
  const datahubTracks = useMemo(() => {
    return channels.filter((t: any) => t?.name?.startsWith('RDH: '))
  }, [channels])

  const handleOpenDataHubClick = () => {
    console.log('handleOpenDataHubClick', showType)
    const fullUrl = window.location.origin + window.location.pathname + '#/data_hub'
    if (showType === 'new') {
      window.open(
        fullUrl,
        'DataHub',
        'width=1200,height=800,left=200,top=200,titlebar=no,status=no,toolbar=no,menubar=no,location=no'
      )
    } else if (showType === 'newTab') {
      window.open(fullUrl, '_blank')
    } else {
      setModalOpen(true)
    }
  }

  const handleCloseModal = () => {
    setModalOpen(false)
  }

  // 监听来自内嵌页面（iframe）的 postMessage：当收到 { type: 'datahub:apply' } 时关闭 modal
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      const payload = event.data
      // 支持直接对象或 JSON 字符串
      let data
      if (typeof payload === 'string') {
        try {
          data = JSON.parse(payload)
        } catch {
          data = payload
        }
      } else {
        data = payload
      }

      if (data && data.type === 'datahub:apply') {
        setModalOpen(false)
      }
    }

    window.addEventListener('message', handleMessage)
    return () => window.removeEventListener('message', handleMessage)
  }, [])

  return (
    <DataHubLeftSideWraaper>
      <AsideMenu name='DataHub' />
      <Box sx={{ px: 1, py: 0.5, pr: '15px', height: 38, display: 'flex', alignItems: 'center' }}>
        <BaimoButton
          variant='outlined'
          size='sm'
          color='primary'
          startDecorator={<FolderOpenRounded sx={{ fontSize: 16 }} />}
          onClick={handleOpenDataHubClick}
          sx={{ width: '100%', fontSize: 12, whiteSpace: 'nowrap' }}>
          Open DataHub
        </BaimoButton>
      </Box>

      <Modal open={modalOpen} onClose={handleCloseModal}>
        <ModalDialog
          variant='outlined'
          sx={{
            width: 'calc(100vw - 80px)',
            height: 'calc(100vh - 80px)',
            p: 0,
            overflow: 'hidden',
            display: 'flex',
            flexDirection: 'column'
          }}>
          <Box component='div' sx={{ flex: 1, overflow: 'hidden' }}>
            <iframe title='DataHub' src={'/#/data_hub'} style={{ width: '100%', height: '100%', border: '0' }} />
          </Box>
        </ModalDialog>
      </Modal>

      <TrackList trackListData={datahubTracks} />
    </DataHubLeftSideWraaper>
  )
}

export default memo(DataHub)
