import React, { memo, useState, useEffect, useRef, useCallback } from 'react'
import type { FC, ReactNode } from 'react'
import Stack from '@mui/joy/Stack'

import AsideMenu from '../../aside-menu'
import { TrackWrapper } from './style'
import AddTrack from './c-cpns/add-track'
import TrackList from './c-cpns/track-list'
import { useRenderer } from '@/store/renderer-ref'

interface Iprops {
  children?: ReactNode
}

/** 轮询间隔 ms — 作为 channelManager 事件的兜底 */
const POLL_INTERVAL = 800

const Tracks: FC<Iprops> = () => {
  const renderer = useRenderer() as any
  const [channels, setChannels] = useState<any[]>([])
  const unsubRef = useRef<(() => void) | null>(null)
  const pollRef = useRef<ReturnType<typeof setInterval> | null>(null)
  const prevJsonRef = useRef<string>('')

  /** 从 channelManager.getAll() 读取最新列表，仅在数据真正变化时 setState */
  const syncFromManager = useCallback(() => {
    if (!renderer?.channelManager) return
    try {
      const all = renderer.channelManager.getAll?.() ?? []
      // 用 JSON 简单比较避免无变化时反复 setState
      const json = JSON.stringify(all)
      if (json !== prevJsonRef.current) {
        prevJsonRef.current = json
        setChannels([...all])
      }
    } catch {
      /* ignore */
    }
  }, [renderer])

  useEffect(() => {
    // Clean up previous subscription & poll
    unsubRef.current?.()
    unsubRef.current = null
    if (pollRef.current) {
      clearInterval(pollRef.current)
      pollRef.current = null
    }

    if (!renderer?.channelManager) {
      setChannels([])
      prevJsonRef.current = ''
      return
    }

    // 1) 初始同步
    syncFromManager()
    console.log('[Track Sidebar] Subscribed to channelManager + polling')

    // 2) 事件驱动：订阅 channelManager 事件，实时响应
    try {
      unsubRef.current = renderer.channelManager.on((event: string, _detail: any) => {
        console.log(`[Track Sidebar] channelManager event: ${event}`)
        syncFromManager()
      })
    } catch (e) {
      console.warn('[Track Sidebar] channelManager.on() failed:', e)
    }

    // 3) 轮询兜底：防止某些操作不触发事件
    pollRef.current = setInterval(syncFromManager, POLL_INTERVAL)

    return () => {
      unsubRef.current?.()
      unsubRef.current = null
      if (pollRef.current) {
        clearInterval(pollRef.current)
        pollRef.current = null
      }
    }
  }, [renderer, syncFromManager])

  return (
    <TrackWrapper>
      <AsideMenu name='Track' />
      <Stack spacing={0} sx={{ width: '100%' }}>
        <AddTrack />
        <TrackList trackListData={channels} />
      </Stack>
    </TrackWrapper>
  )
}

export default memo(Tracks)
