import React, { memo, useRef, useState } from 'react'
import type { FC, ReactNode } from 'react'
import Stack from '@mui/joy/Stack'
import Box from '@mui/joy/Box'
import AddIcon from '@mui/icons-material/Add'
import RemoveIcon from '@mui/icons-material/Remove'
import FolderOpenIcon from '@mui/icons-material/FolderOpen'
import LanguageIcon from '@mui/icons-material/Language'
import OpenInNewIcon from '@mui/icons-material/OpenInNew'

import { useRenderer } from '@/store/renderer-ref'
import { AddTrackWrapper } from './style'
import BaimoButton from '@/components/button'

interface Iprops {
  children?: ReactNode
}

/** 文件选择器 accept 属性 */
const LOCAL_FILE_ACCEPT =
  '.bam,.bai,.vcf.gz,.tbi,.bigwig,.bw,.bigbed,.bb,.bed.gz,.bed,.gff.gz,.gff3.gz,.gtf.gz,.gff,.gff3,.gtf,.fasta,.fa,.fasta.gz,.fa.gz,.fai,.gzi,.cram,.crai,.ism.gz,.vcf,.bedgraph,.bg,.rmgff,.rmbed,.fna,.fna.gz'

const AddTrack: FC<Iprops> = () => {
  const renderer = useRenderer() as any
  const fileInputRef = useRef<HTMLInputElement | null>(null)
  const isApplication = import.meta.env.VITE_IS_APPLICATION === 'true'
  const [showButtons, setShowButtons] = useState(false)

  // ── Local File Import ──
  const handleLocalClick = () => {
    fileInputRef.current?.click()
  }

  const onFilesSelected = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files ?? [])
    if (!files.length || !renderer) return
    console.log(
      '[AddTrack] importLocalFiles:',
      files.map((f) => f.name)
    )
    renderer.importLocalFiles(files)
    // 允许重复选择同名文件
    e.target.value = ''
  }

  // ── Remote URL Import ──
  const handleRemoteClick = () => {
    if (!renderer) return
    console.log('[AddTrack] importRemoteUrl (dialog)')
    renderer.importRemoteUrl()
  }

  // ── DataHub ──
  const handleOpenDataHubClick = () => {
    const fullUrl = window.location.origin + window.location.pathname + '#/data_hub'
    if (isApplication) {
      window.open(fullUrl, '_blank')
    } else {
      window.open(
        fullUrl,
        'DataHub',
        'width=1200,height=800,left=200,top=200,titlebar=no,status=no,toolbar=no,menubar=no,location=no'
      )
    }
  }

  // ── Listen for track actions from context menu ──
  React.useEffect(() => {
    const handleTrackAction = (event: CustomEvent) => {
      const action = event.detail.action
      console.log('[AddTrack] Track action from menu:', action)

      switch (action) {
        case 'add-local':
          fileInputRef.current?.click()
          break
        case 'add-remote':
          if (renderer) renderer.importRemoteUrl()
          break
        case 'open-datahub':
          handleOpenDataHubClick()
          break
      }
    }

    window.addEventListener('track-action', handleTrackAction as EventListener)
    return () => {
      window.removeEventListener('track-action', handleTrackAction as EventListener)
    }
  }, [renderer])

  return (
    <AddTrackWrapper>
      {/* Hidden file input */}
      <input
        ref={fileInputRef}
        type='file'
        multiple
        style={{ display: 'none' }}
        onChange={onFilesSelected}
        accept={LOCAL_FILE_ACCEPT}
      />

      {/* "+ Add Channel" toggle button — full width */}
      <Box sx={{ px: 1, py: 0.5, pr: '15px', height: 38, display: 'flex', alignItems: 'center' }}>
        <BaimoButton
          variant='outlined'
          size='sm'
          color='primary'
          startDecorator={showButtons ? <RemoveIcon sx={{ fontSize: 16 }} /> : <AddIcon sx={{ fontSize: 16 }} />}
          onClick={() => setShowButtons(!showButtons)}
          sx={{ width: '100%', fontSize: 12, whiteSpace: 'nowrap' }}>
          Add Channel
        </BaimoButton>
      </Box>

      {/* Collapsible buttons */}
      {showButtons && (
        <Stack direction='column' spacing={0.5} sx={{ px: 1, pb: 0.5, pr: '15px' }}>
          <BaimoButton
            variant='solid'
            size='sm'
            color='primary'
            startDecorator={<FolderOpenIcon sx={{ fontSize: 14 }} />}
            onClick={handleLocalClick}
            sx={{ fontSize: 11, whiteSpace: 'nowrap' }}>
            Add Track By Local
          </BaimoButton>

          <BaimoButton
            variant='solid'
            size='sm'
            color='primary'
            startDecorator={<LanguageIcon sx={{ fontSize: 14 }} />}
            onClick={handleRemoteClick}
            sx={{ fontSize: 11, whiteSpace: 'nowrap' }}>
            Add Track By Remote
          </BaimoButton>

          <BaimoButton
            variant='solid'
            size='sm'
            color='primary'
            startDecorator={<OpenInNewIcon sx={{ fontSize: 14 }} />}
            onClick={handleOpenDataHubClick}
            sx={{ fontSize: 11, whiteSpace: 'nowrap' }}>
            Add Track By DataHub
          </BaimoButton>
        </Stack>
      )}
    </AddTrackWrapper>
  )
}

export default memo(AddTrack)
