import React, { memo } from 'react'
import type { FC, ReactNode } from 'react'
import { CloudDownloadOutlined, BugOutlined, AlertOutlined, ApiOutlined } from '@ant-design/icons'
import { MainFooterWrapper } from './style'

interface Iprops {
  children?: ReactNode
}

const MainFooter: FC<Iprops> = () => {
  return (
    <MainFooterWrapper>
      <div className='main-foot'>
        <BugOutlined className='footer-btn' />
        <AlertOutlined className='footer-btn' />
        <ApiOutlined className='footer-btn' />
        <CloudDownloadOutlined className='footer-btn' />
      </div>
    </MainFooterWrapper>
  )
}

export default memo(MainFooter)
