import React, { memo, useState, useEffect, useMemo, useCallback, useRef } from 'react'
import type { FC, ReactNode } from 'react'

import { getPanel, IPanelConf, panelConf, getComponent } from '@/config/panel-conf'
import { Layout } from 'antd'
import LeftAsider from '@/views/main/c-cpns/left-asider'
import RightAsider from '@/views/main/c-cpns/right-asider'
import MainMenu from '@/views/main/c-cpns/main-menu'
import MainFooter from '@/views/main/c-cpns/footer'
import Home from './c-cpns/left-asider/home'
import Track from './c-cpns/left-asider/track'
import Chat from './c-views/chat'
import { useIsMobile } from '@/utils/useIsMobile'
import { Dialog, DialogTitle, DialogContent, DialogActions, Button, Typography, Chip, Box } from '@mui/material'

import { Allotment } from 'allotment'
import 'allotment/dist/style.css'
import { MainWrapper } from './style'
import { shallowEqualApp, useAppDispatch, useAppSelecter } from '@/store'
import { setPlugins, setCurrentLeftAsideTab } from '@/store/modules/rna_browser_settings'
import { getRenderer } from '@/store/renderer-ref'

const { Content } = Layout

export interface IMainPanelConf {
  label: string
  left_asider: {
    show: boolean
  }
  right_asider: {
    show: boolean
  }
}

const mainPanelConf: IMainPanelConf = {
  label: 'main',
  left_asider: {
    show: true
  },
  right_asider: {
    show: true
  }
}

interface Iprops {
  children?: ReactNode
}

function getWindowDimensions() {
  const { innerWidth: width, innerHeight: height } = window
  return {
    width,
    height
  }
}

const Main: FC<Iprops> = () => {
  const [windowDimensions, setWindowDimensions] = useState(getWindowDimensions())
  const isMobile = useIsMobile()

  // left aside
  const [asideElement, setasideElement] = useState(<Home />)

  // right aside
  const [rightAsideMaxWidth, setRightAsideMaxWidth] = useState(5000)
  const [isShowLeftAside, setisShowLeftAside] = useState(mainPanelConf.left_asider.show)
  const [isShowRightAside, setisShowRightAside] = useState(mainPanelConf.right_asider.show)
  const [middlePanel, setMiddlePanel] = useState<IPanelConf[]>(getPanel(panelConf, 'middle'))
  const [rightPanel, setRightPanel] = useState<IPanelConf[]>(getPanel(panelConf, 'right'))

  // Duplicate channel dialog state
  const [dupDialogOpen, setDupDialogOpen] = useState(false)
  const [dupDialogSkipped, setDupDialogSkipped] = useState<string[]>([])
  const dupDialogItemsRef = useRef<{ file_url: string; name: string; file_format: string }[]>([])

  // Compute the detailed info for skipped items (for dialog display)
  const dupDialogDetails = useMemo(() => {
    const items = dupDialogItemsRef.current
    return dupDialogSkipped.map((channelName) => {
      const item = items.find((i) => 'RDH: ' + i.name === channelName)
      if (!item) return { name: channelName, format: '', url: '', indexUrl: '' }
      const fmt = (item.file_format || '').toLowerCase()
      let indexUrl = ''
      if (['bed', 'vcf', 'gff', 'gff3', 'gtf'].includes(fmt)) indexUrl = item.file_url + '.tbi'
      else if (fmt === 'bam') indexUrl = item.file_url + '.bai'
      else if (fmt === 'cram') indexUrl = item.file_url + '.crai'
      else if (['fasta', 'fa', 'fna'].includes(fmt)) indexUrl = item.file_url + '.fai'
      return { name: channelName, format: item.file_format?.toUpperCase() || '', url: item.file_url, indexUrl }
    })
  }, [dupDialogSkipped])

  const dispatch = useAppDispatch()
  const { plugins, currentLeftAsideTab } = useAppSelecter(
    (state) => ({
      plugins: (state.rbSettings.plugins ?? []) as IPanelConf[],
      currentLeftAsideTab: state.rbSettings.currentLeftAsideTab
    }),
    shallowEqualApp
  )

  // 初始化：如为空或数据无效，用 panelConf 回填
  useEffect(() => {
    if (!plugins || plugins.length === 0) {
      dispatch(setPlugins(panelConf as any))
    } else {
      // 检查是否有无效的 componentId
      const hasInvalidData = plugins.some((p) => !p.componentId)
      if (hasInvalidData) {
        console.warn('Detected invalid plugin data in store, resetting to default configuration')
        dispatch(setPlugins(panelConf as any))
      }
    }
  }, [dispatch, plugins])

  useEffect(() => {
    const newMiddlePanel = getPanel(plugins, 'middle')
    const newRightPanel = getPanel(plugins, 'right')

    console.log('=== PANEL DEBUG ===')
    console.log(
      'Middle panels:',
      newMiddlePanel.map((p) => ({ name: p.name, componentId: p.componentId }))
    )
    console.log(
      'Right panels:',
      newRightPanel.map((p) => ({ name: p.name, componentId: p.componentId }))
    )

    setMiddlePanel(newMiddlePanel)
    setRightPanel(newRightPanel)
  }, [plugins])

  function getAsideElement(ele: any) {
    if (currentLeftAsideTab !== ele.label) {
      setasideElement(ele.element)
      dispatch(setCurrentLeftAsideTab(ele.label))
    }
    console.log('getAsideElement', ele)
  }

  // 监听 Redux store 中的 currentLeftAsideTab 变化
  useEffect(() => {
    import('@/config/left-aside-conf').then((module) => {
      const asideData = module.default
      const targetItem = asideData.find((item) => item.label === currentLeftAsideTab)
      if (targetItem) {
        setasideElement(targetItem.element)
      }
    })
  }, [currentLeftAsideTab])

  // ── DataHub batch import: 读取 selectorData 并通过 renderer.importRemoteUrl 批量导入 ──
  const handleDataHubImport = () => {
    const raw = localStorage.getItem('selectorData')
    if (!raw) return
    try {
      const items: { file_url: string; name: string; file_format: string }[] = JSON.parse(raw)
      if (!Array.isArray(items) || items.length === 0) return

      const renderer = getRenderer() as any
      if (!renderer?.importRemoteUrl) {
        console.warn('[DataHub] renderer or importRemoteUrl not available')
        return
      }

      // ── 去重：与当前 renderer track list 比较，跳过同名 channel ──
      const existingNames = new Set<string>()
      try {
        const allChannels = renderer.channelManager?.getAll() ?? []
        for (const ch of allChannels) {
          if (ch.name) existingNames.add(ch.name)
        }
      } catch {
        // channelManager 可能不可用，继续不阻断
      }

      const skipped: string[] = []
      const batch: { url: string; name: string; indexUrl?: string }[] = []

      for (const item of items) {
        const channelName = 'RDH: ' + item.name
        if (existingNames.has(channelName)) {
          skipped.push(channelName)
          continue
        }

        // ── 根据 file_format 判断是否需要 index URL ──
        const fmt = (item.file_format || '').toLowerCase()
        let indexUrl: string | undefined
        if (fmt === 'bed' || fmt === 'vcf') {
          // file_url 通常已是 .bed.gz / .vcf.gz，index 是同路径 + .tbi
          indexUrl = item.file_url + '.tbi'
        } else if (fmt === 'gff' || fmt === 'gff3' || fmt === 'gtf') {
          indexUrl = item.file_url + '.tbi'
        } else if (fmt === 'bam') {
          indexUrl = item.file_url + '.bai'
        } else if (fmt === 'cram') {
          indexUrl = item.file_url + '.crai'
        } else if (fmt === 'fasta' || fmt === 'fa' || fmt === 'fna') {
          indexUrl = item.file_url + '.fai'
        }
        // bigWig / bigBed 等自索引格式不需要 index

        batch.push({
          url: item.file_url,
          name: channelName,
          ...(indexUrl ? { indexUrl } : {})
        })
      }

      // ── Handle duplicate channels ──
      if (skipped.length > 0 && batch.length > 0) {
        // Has both duplicates and new channels: import new ones, ask about duplicates
        console.log('[DataHub] importRemoteUrl batch (non-duplicate):', batch)
        renderer.importRemoteUrl(batch)
        console.warn('[DataHub] Duplicate channels found:', skipped)
        dupDialogItemsRef.current = items
        setDupDialogSkipped(skipped)
        setDupDialogOpen(true)
      } else if (skipped.length > 0 && batch.length === 0) {
        // All channels are duplicates
        console.warn('[DataHub] All channels are duplicates:', skipped)
        dupDialogItemsRef.current = items
        setDupDialogSkipped(skipped)
        setDupDialogOpen(true)
      } else if (batch.length > 0) {
        console.log('[DataHub] importRemoteUrl batch:', batch)
        renderer.importRemoteUrl(batch)
      }
    } catch (e) {
      console.error('[DataHub] Failed to parse selectorData:', e)
    } finally {
      localStorage.removeItem('selectorData')
    }
  }

  // Handle "Load Duplicate Channels" button in the dialog
  const handleLoadDuplicates = useCallback(() => {
    setDupDialogOpen(false)
    const renderer = getRenderer() as any
    if (!renderer?.importRemoteUrl) return

    const items = dupDialogItemsRef.current
    const duplicateBatch: { url: string; name: string; indexUrl?: string }[] = []

    for (const item of items) {
      const channelName = 'RDH: ' + item.name
      if (!dupDialogSkipped.includes(channelName)) continue

      const fmt = (item.file_format || '').toLowerCase()
      let indexUrl: string | undefined
      if (fmt === 'bed' || fmt === 'vcf') indexUrl = item.file_url + '.tbi'
      else if (fmt === 'gff' || fmt === 'gff3' || fmt === 'gtf') indexUrl = item.file_url + '.tbi'
      else if (fmt === 'bam') indexUrl = item.file_url + '.bai'
      else if (fmt === 'cram') indexUrl = item.file_url + '.crai'
      else if (fmt === 'fasta' || fmt === 'fa' || fmt === 'fna') indexUrl = item.file_url + '.fai'

      duplicateBatch.push({
        url: item.file_url,
        name: channelName,
        ...(indexUrl ? { indexUrl } : {})
      })
    }

    if (duplicateBatch.length > 0) {
      console.log('[DataHub] Force-loading duplicate channels:', duplicateBatch)
      renderer.importRemoteUrl(duplicateBatch)
    }
  }, [dupDialogSkipped])

  useEffect(() => {
    // 1. iframe/modal: 监听 postMessage 中的 datahub:apply
    const handleMessage = (event: MessageEvent) => {
      let data = event.data
      if (typeof data === 'string') {
        try {
          data = JSON.parse(data)
        } catch {
          return
        }
      }
      if (data?.type === 'datahub:apply') {
        handleDataHubImport()
      }
    }

    // 2. 新窗口 / 新标签页: 监听 storage 事件 (selectorData 被写入时触发)
    const handleStorage = (event: StorageEvent) => {
      if (event.key === 'selectorData' && event.newValue) {
        handleDataHubImport()
      }
    }

    window.addEventListener('message', handleMessage)
    window.addEventListener('storage', handleStorage)
    return () => {
      window.removeEventListener('message', handleMessage)
      window.removeEventListener('storage', handleStorage)
    }
  }, [])

  const getRightAsideElement = (ele: any) => {
    if (isShowRightAside) {
      setRightAsideMaxWidth(300)
    } else {
      setRightAsideMaxWidth(500)
    }
    console.log('getRightAsideElement', ele, isShowRightAside)
    setisShowRightAside(!isShowRightAside)
    fixedRightAside()
  }

  const fixedRightAside = () => {
    setRightAsideMaxWidth(500)
    const setWidthTimer = setTimeout(() => {
      setRightAsideMaxWidth(5000)
      clearTimeout(setWidthTimer)
    }, 200)
  }

  useEffect(() => {
    function handleResize() {
      setWindowDimensions(getWindowDimensions())
    }
    window.addEventListener('resize', handleResize)
    return () => window.removeEventListener('resize', handleResize)
  }, [])

  return (
    <MainWrapper>
      <Layout>
        <MainMenu />
        <Layout style={{ height: 'calc(100vh - 51px)' }}>
          {!isMobile && <LeftAsider getAsideElement={getAsideElement}></LeftAsider>}

          <Content id='baimo-asider'>
            <div style={{ height: '100%', width: '100%' }}>
              <Allotment defaultSizes={[200, windowDimensions.height - 500, 300]}>
                {/* <Panel text='abc' />
                <Panel text='123' />
                <Panel text='def' /> */}
                {isShowLeftAside && !isMobile && (
                  <Allotment.Pane maxSize={240} minSize={0}>
                    <div id='left-asider-content' style={{ height: '100%', background: '#ffffff' }}>
                      {asideElement}
                    </div>
                  </Allotment.Pane>
                )}

                {middlePanel.length > 0 && (
                  <Allotment vertical defaultSizes={[windowDimensions.height / 2, windowDimensions.height / 2]}>
                    {middlePanel.map((panel, i) => {
                      const Component = getComponent(panel.componentId)
                      if (!Component) {
                        console.warn(`Skipping panel ${panel.name} - component not found for ID: ${panel.componentId}`)
                        return null
                      }
                      return (
                        <Allotment.Pane minSize={34} key={i}>
                          <Component />
                        </Allotment.Pane>
                      )
                    })}
                  </Allotment>
                )}

                {rightPanel.length > 0 && isShowRightAside && (
                  // <Allotment.Pane minSize={0} maxSize={rightAsideMaxWidth}>
                  <Allotment.Pane minSize={0} maxSize={Math.round(windowDimensions.width / 3)}>
                    <div id='right-panel-area' style={{ height: '100%', width: '100%' }}>
                      <Allotment vertical>
                        {rightPanel.map((panel, i) => {
                          const Component = getComponent(panel.componentId)
                          if (!Component) {
                            console.warn(
                              `Skipping panel ${panel.name} - component not found for ID: ${panel.componentId}`
                            )
                            return null
                          }
                          return (
                            <Allotment.Pane minSize={34} key={i}>
                              <Component />
                            </Allotment.Pane>
                          )
                        })}
                      </Allotment>
                    </div>
                  </Allotment.Pane>
                )}
              </Allotment>
            </div>
          </Content>
          {!isMobile && <RightAsider getAsideElement={getRightAsideElement}></RightAsider>}
        </Layout>
        <MainFooter />
        <Chat renderer={null as any} />
      </Layout>

      {/* Duplicate channels confirmation dialog */}
      <Dialog
        open={dupDialogOpen}
        onClose={() => setDupDialogOpen(false)}
        PaperProps={{ sx: { borderRadius: 3, minWidth: 420, maxWidth: 520 } }}>
        <DialogTitle sx={{ fontWeight: 600, fontSize: 18, pb: 1 }}>Duplicate Channels</DialogTitle>
        <DialogContent sx={{ pt: '8px !important' }}>
          <Typography variant='body2' color='text.secondary' sx={{ mb: 2 }}>
            {dupDialogSkipped.length === 1
              ? 'The following channel already exists:'
              : `The following ${dupDialogSkipped.length} channels already exist:`}
          </Typography>
          <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5, maxHeight: 320, overflow: 'auto' }}>
            {dupDialogDetails.map((item, idx) => (
              <Box key={idx} sx={{ bgcolor: '#f8f9fa', borderRadius: 2, px: 2, py: 1.5 }}>
                <Box sx={{ display: 'flex', gap: 1.5, mb: 0.5 }}>
                  <Typography
                    variant='caption'
                    color='text.secondary'
                    sx={{ minWidth: 56, textAlign: 'right', pt: 0.25 }}>
                    NAME
                  </Typography>
                  <Typography
                    variant='body2'
                    sx={{
                      fontWeight: 500,
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                      flex: 1
                    }}>
                    {item.name}
                  </Typography>
                </Box>
                <Box sx={{ display: 'flex', gap: 1.5, mb: 0.5, alignItems: 'center' }}>
                  <Typography variant='caption' color='text.secondary' sx={{ minWidth: 56, textAlign: 'right' }}>
                    FORMAT
                  </Typography>
                  {item.format && (
                    <Chip
                      label={item.format}
                      size='small'
                      color='primary'
                      sx={{ height: 20, fontSize: 11, fontWeight: 600 }}
                    />
                  )}
                </Box>
                <Box sx={{ display: 'flex', gap: 1.5, mb: 0.5 }}>
                  <Typography
                    variant='caption'
                    color='text.secondary'
                    sx={{ minWidth: 56, textAlign: 'right', pt: 0.25 }}>
                    URL
                  </Typography>
                  <Typography
                    variant='body2'
                    color='text.secondary'
                    sx={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1, fontSize: 12 }}>
                    {item.url}
                  </Typography>
                </Box>
                {item.indexUrl && (
                  <Box sx={{ display: 'flex', gap: 1.5 }}>
                    <Typography
                      variant='caption'
                      color='text.secondary'
                      sx={{ minWidth: 56, textAlign: 'right', pt: 0.25 }}>
                      INDEX
                    </Typography>
                    <Typography
                      variant='body2'
                      color='text.secondary'
                      sx={{
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                        flex: 1,
                        fontSize: 12
                      }}>
                      {item.indexUrl}
                    </Typography>
                  </Box>
                )}
              </Box>
            ))}
          </Box>
        </DialogContent>
        <DialogActions sx={{ px: 3, pb: 2.5, pt: 1 }}>
          <Button
            onClick={() => setDupDialogOpen(false)}
            sx={{ color: '#666', textTransform: 'none', fontWeight: 500 }}>
            Cancel
          </Button>
          <Button
            onClick={handleLoadDuplicates}
            variant='contained'
            disableElevation
            sx={{ textTransform: 'none', fontWeight: 600, borderRadius: 1.5, px: 3 }}>
            Load Duplicate Channels
          </Button>
        </DialogActions>
      </Dialog>
    </MainWrapper>
  )
}

export default memo(Main)
