import React, { memo, useEffect, useState, useMemo, useCallback } from 'react'
import type { FC, ReactNode } from 'react'
import { useAppDispatch } from '@/store'
import AsideMenu from '@/views/main/c-cpns/left-asider/c-cpns/index'
import { HistoryWraaper } from './style'

import { Box, Typography, Input, Divider } from '@mui/joy'
import List from '@mui/material/List'
import ListItemButton from '@mui/material/ListItemButton'
import ListItemText from '@mui/material/ListItemText'
import MuiDivider from '@mui/material/Divider'
import IconButton from '@mui/material/IconButton'
import ExpandMoreIcon from '@mui/icons-material/ExpandMore'
import KeyboardArrowRightIcon from '@mui/icons-material/KeyboardArrowRight'
import SearchIcon from '@mui/icons-material/Search'
import CloseIcon from '@mui/icons-material/Close'
import RefreshIcon from '@mui/icons-material/Refresh'
import DeleteIcon from '@mui/icons-material/DeleteOutline'

import { setCurrentRegion, type IRBRegion } from '@/store/modules/rna_browser_settings'
import { historyManager } from '@rbrowser/main'
import { useRenderer } from '@/store/renderer-ref'

interface HistoryItem {
  region: string
  timestamp: number
}

interface Iprops {
  children?: ReactNode
}

/* ───── region 字符串解析（与 Favorites 共用逻辑） ───── */

const COORD_RE = /^(chr\w+):(\d+)-(\d+)$/i
// 支持 name:offset 和 name:offset:trans_type 两种格式
const TRANSCRIPT_RE = /^(.+?):(\d+)(?::(.+))?$/

interface ParsedHistoryItem {
  raw: string
  displayName: string
  secondary: string
  timestamp: number
  transType?: string
  isCoord: boolean
  rbRegion: IRBRegion
}

function parseHistoryItem(item: HistoryItem): ParsedHistoryItem {
  const region = item.region

  // 坐标格式 chr1:100-200
  const coordMatch = region.match(COORD_RE)
  if (coordMatch) {
    const chr = coordMatch[1]
    const start = parseInt(coordMatch[2], 10)
    const end = parseInt(coordMatch[3], 10)
    return {
      raw: region,
      displayName: region,
      secondary: `${(end - start).toLocaleString()} bp`,
      timestamp: item.timestamp,
      isCoord: true,
      rbRegion: { chr, start, end }
    }
  }

  // Transcript:offset 或 Transcript:offset:trans_type 格式
  const transMatch = region.match(TRANSCRIPT_RE)
  if (transMatch) {
    const name = transMatch[1]
    const offset = parseInt(transMatch[2], 10)
    const transType = transMatch[3] || undefined
    return {
      raw: region,
      displayName: name,
      secondary: `±${offset.toLocaleString()} bp`,
      timestamp: item.timestamp,
      transType,
      isCoord: false,
      rbRegion: { chr: '', start: 0, end: 0, trans_name: name, offset, level: 'RNA' }
    }
  }

  return {
    raw: region,
    displayName: region,
    secondary: '',
    timestamp: item.timestamp,
    isCoord: false,
    rbRegion: { chr: '', start: 0, end: 0, trans_name: region }
  }
}

/** TransType 徽标（参考 Search 面板的 TransTypeBadge） */
const TransTypeBadge: React.FC<{ transType?: string; isCoord?: boolean; size?: number }> = ({
  transType,
  isCoord,
  size = 18
}) => {
  // 使用 R/D/C 徽标替代 trans_type 徽标
  const MODE_BADGE: Record<string, { color: string; char: string }> = {
    rna: { color: '#00b894', char: 'R' },
    dna: { color: '#3867d6', char: 'D' },
    cds: { color: '#f58518', char: 'C' }
  }
  // 根据 transType 推断模式：坐标→DNA，带 trans_type→RNA
  let mode = 'rna'
  if (isCoord) mode = 'dna'
  const badge = MODE_BADGE[mode] ?? MODE_BADGE.rna
  return (
    <Box
      component='span'
      sx={{
        width: size,
        height: size,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center',
        borderRadius: '3px',
        backgroundColor: badge.color,
        color: '#fff',
        fontSize: 10,
        fontWeight: 700,
        lineHeight: 1,
        flex: '0 0 auto',
        userSelect: 'none'
      }}>
      {badge.char}
    </Box>
  )
}

/* ───── 日期分组 ───── */

type DateGroup = {
  label: string
  sortTime: number
  items: ParsedHistoryItem[]
}

function getDateLabel(ts: number): string {
  const now = new Date()
  const d = new Date(ts)
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate())
  const yesterday = new Date(today.getTime() - 86400000)
  const thisWeek = new Date(today.getTime() - 6 * 86400000)

  if (d >= today) return 'Today'
  if (d >= yesterday) return 'Yesterday'
  if (d >= thisWeek) return 'This Week'
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

function buildDateGroups(items: ParsedHistoryItem[]): DateGroup[] {
  const map = new Map<string, ParsedHistoryItem[]>()
  const sortMap = new Map<string, number>()

  for (const it of items) {
    const label = getDateLabel(it.timestamp)
    if (!map.has(label)) {
      map.set(label, [])
      sortMap.set(label, it.timestamp)
    }
    map.get(label)!.push(it)
  }

  const groups: DateGroup[] = []
  for (const [label, items] of map) {
    groups.push({ label, sortTime: sortMap.get(label)!, items })
  }
  // 按最近时间排序（新 → 旧）
  groups.sort((a, b) => b.sortTime - a.sortTime)
  return groups
}

/* ───── 组件 ───── */

/** 每隔 REFRESH_MS 重新读取 historyManager */
const REFRESH_MS = 2000
const MAX_HISTORY = 100

const History: FC<Iprops> = () => {
  const dispatch = useAppDispatch()

  // 获取 renderer 以检测当前模式
  const renderer = useRenderer() as any

  /** 从 historyManager 读取历史（定时刷新，因为 HistoryManager 无 on() 事件） */
  const [rawItems, setRawItems] = useState<HistoryItem[]>(() => historyManager.getHistory(MAX_HISTORY))

  useEffect(() => {
    // 初始同步
    setRawItems(historyManager.getHistory(MAX_HISTORY))
    // 定时刷新
    const timer = setInterval(() => {
      setRawItems(historyManager.getHistory(MAX_HISTORY))
    }, REFRESH_MS)
    return () => clearInterval(timer)
  }, [])

  /** 搜索框状态 + 去抖 */
  const [query, setQuery] = useState('')
  const [debounced, setDebounced] = useState(query)
  useEffect(() => {
    const t = setTimeout(() => setDebounced(query.trim()), 180)
    return () => clearTimeout(t)
  }, [query])

  /** 解析 → 过滤 → 分组 */
  const groups = useMemo(() => {
    const parsed = rawItems.map(parseHistoryItem)
    const q = debounced.toLowerCase()
    const filtered = q
      ? parsed.filter((p) => p.displayName.toLowerCase().includes(q) || p.raw.toLowerCase().includes(q))
      : parsed
    return buildDateGroups(filtered)
  }, [rawItems, debounced])

  /** 折叠状态 */
  const [expanded, setExpanded] = useState<Set<string>>(new Set(['Today']))
  useEffect(() => {
    if (groups.length === 0) return
    setExpanded((prev) => {
      if (prev.size > 0) return prev
      const hasToday = groups.some((g) => g.label === 'Today')
      return new Set(hasToday ? ['Today'] : [groups[0].label])
    })
  }, [groups])

  // 搜索时全展开，清空搜索时恢复默认（仅当 debounced 实际变化时触发）
  const prevDebouncedRef = React.useRef(debounced)
  useEffect(() => {
    const prevDebounced = prevDebouncedRef.current
    prevDebouncedRef.current = debounced
    if (debounced) {
      setExpanded(new Set(groups.map((g) => g.label)))
    } else if (prevDebounced && !debounced && groups.length > 0) {
      // 仅在从有搜索词变为空时重置展开状态
      const hasToday = groups.some((g) => g.label === 'Today')
      setExpanded(new Set(hasToday ? ['Today'] : [groups[0].label]))
    }
  }, [debounced, groups])

  const toggleGroup = (label: string) => {
    setExpanded((prev) => {
      const next = new Set(prev)
      if (next.has(label)) next.delete(label)
      else next.add(label)
      return next
    })
  }

  /** 高度适配 */
  const [maxHeight, setMaxHeight] = useState<number>(window.innerHeight - 85)
  useEffect(() => {
    const onResize = () => setMaxHeight(window.innerHeight - 85)
    window.addEventListener('resize', onResize)
    return () => window.removeEventListener('resize', onResize)
  }, [])

  /** 点击条目 → 导航（根据当前 renderer 模式决定 RNA / CDS） */
  const handleClick = useCallback(
    (p: ParsedHistoryItem) => {
      const region = { ...p.rbRegion }
      // 如果是 transcript 格式，根据当前 renderer 模式设定导航方式
      if (region.trans_name && renderer) {
        if (renderer.isCdsMode) {
          region.level = 'CDS'
        } else {
          region.level = 'RNA'
        }
      }
      dispatch(setCurrentRegion(region))
    },
    [dispatch, renderer]
  )

  /** 删除单条历史 */
  const handleDelete = useCallback((region: string) => {
    historyManager.remove(region)
    setRawItems(historyManager.getHistory(MAX_HISTORY))
  }, [])

  /** 清空历史 */
  const handleClearAll = useCallback(() => {
    historyManager.clearHistory()
    setRawItems([])
  }, [])

  /** 格式化时间 */
  const formatTime = (ts: number) => {
    const d = new Date(ts)
    return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' })
  }

  return (
    <HistoryWraaper>
      <AsideMenu name='History' />
      <div className='content' style={{ height: maxHeight, flex: 1, overflowY: 'auto', position: 'relative' }}>
        {/* 顶部搜索框（吸顶） */}
        <Box
          sx={{
            position: 'sticky',
            top: 0,
            zIndex: 3,
            bgcolor: 'background.body',
            borderBottom: '1px solid',
            borderColor: 'divider',
            p: '3px 8px',
            height: 38,
            display: 'flex',
            gap: 0.5,
            alignItems: 'center',
            boxShadow: 'none'
          }}>
          <Input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder='Search history…'
            size='sm'
            sx={{
              flex: 1,
              p: '3px',
              '--Input-focusedThickness': '0px',
              '--variant-borderWidth': '0px',
              border: 'none',
              boxShadow: 'none',
              backgroundColor: 'transparent',
              '&::before': { display: 'none' }
            }}
            startDecorator={<SearchIcon fontSize='small' />}
            endDecorator={
              query ? (
                <IconButton size='small' onClick={() => setQuery('')} sx={{ p: 0.25 }}>
                  <CloseIcon fontSize='small' />
                </IconButton>
              ) : null
            }
            slotProps={{ input: { 'aria-label': 'Search history' } }}
          />
          {rawItems.length > 0 && (
            <IconButton size='small' onClick={handleClearAll} title='Clear all history' sx={{ p: 0.5 }}>
              <RefreshIcon fontSize='small' sx={{ color: '#3867d6' }} />
            </IconButton>
          )}
        </Box>

        {/* 列表内容 */}
        {groups.length > 0 ? (
          <List dense disablePadding>
            {groups.map((g) => {
              const isOpen = expanded.has(g.label)
              return (
                <React.Fragment key={`${g.label}-${g.sortTime}`}>
                  {/* 组标题（可折叠） */}
                  <Box sx={{ px: 1, py: 0.25, display: 'flex', alignItems: 'center', gap: 0.25 }}>
                    <IconButton
                      size='small'
                      onClick={() => toggleGroup(g.label)}
                      sx={{ mr: 0.25, p: 0.25 }}
                      aria-label={(isOpen ? 'Collapse ' : 'Expand ') + g.label}>
                      {isOpen ? <ExpandMoreIcon fontSize='small' /> : <KeyboardArrowRightIcon fontSize='small' />}
                    </IconButton>

                    <Typography
                      noWrap
                      sx={{
                        px: 0.5,
                        py: 0.5,
                        fontSize: 12,
                        color: 'neutral.500',
                        textTransform: 'uppercase',
                        letterSpacing: 0.3,
                        userSelect: 'none',
                        flex: 1,
                        overflow: 'hidden',
                        textOverflow: 'ellipsis'
                      }}>
                      {g.label}
                    </Typography>

                    <Typography
                      component='span'
                      sx={{
                        fontSize: 12,
                        color: 'neutral.500',
                        fontWeight: 500,
                        minWidth: 24,
                        textAlign: 'right',
                        ml: 0.5,
                        flex: '0 0 auto'
                      }}>
                      {g.items.length}
                    </Typography>
                  </Box>

                  {/* 组内容 */}
                  {isOpen &&
                    g.items.map((p, i) => (
                      <ListItemButton
                        key={`${p.raw}-${p.timestamp}-${i}`}
                        dense
                        onClick={() => handleClick(p)}
                        sx={{ pr: '5px', gap: 0, alignItems: 'center' }}>
                        <Box sx={{ mr: 0.75, flex: '0 0 auto' }}>
                          <TransTypeBadge transType={p.transType} isCoord={p.isCoord} size={16} />
                        </Box>

                        <ListItemText
                          primary={p.displayName}
                          secondary={`${formatTime(p.timestamp)}${p.secondary ? ' · ' + p.secondary : ''}`}
                          primaryTypographyProps={{ fontSize: 12, noWrap: true }}
                          secondaryTypographyProps={{ fontSize: 10, color: 'text.disabled' }}
                          sx={{
                            pl: '5px',
                            m: 0,
                            whiteSpace: 'nowrap',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis'
                          }}
                        />

                        {/* 悬浮删除按钮 */}
                        <Box
                          sx={{
                            ml: 'auto',
                            display: 'flex',
                            alignItems: 'center',
                            opacity: 0,
                            transition: 'opacity 0.2s',
                            '.MuiListItemButton-root:hover &': { opacity: 1 }
                          }}>
                          <IconButton
                            size='small'
                            onClick={(e) => {
                              e.stopPropagation()
                              handleDelete(p.raw)
                            }}
                            sx={{ color: 'grey.500', p: 0.25, fontSize: 18 }}>
                            <DeleteIcon fontSize='inherit' />
                          </IconButton>
                        </Box>
                      </ListItemButton>
                    ))}
                  <MuiDivider sx={{ my: 0.5 }} />
                </React.Fragment>
              )
            })}
          </List>
        ) : null}

        {/* 空态 */}
        {rawItems.length === 0 && (
          <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
            No history <br /> Navigation history will be automatically recorded here in RBrowser.
          </Typography>
        )}
        {rawItems.length > 0 && groups.length === 0 && (
          <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
            No matches <br /> Try another keyword.
          </Typography>
        )}
      </div>
    </HistoryWraaper>
  )
}

export default memo(History)
