import { useState, useEffect } from 'react'

/**
 * Detect if the current device is mobile via User-Agent + touch capability.
 * Returns a stable boolean that updates on resize (e.g. DevTools device toggle).
 */
export function useIsMobile(): boolean {
  const [isMobile, setIsMobile] = useState(() => detectMobile())
  useEffect(() => {
    const handleResize = () => setIsMobile(detectMobile())
    window.addEventListener('resize', handleResize)
    return () => window.removeEventListener('resize', handleResize)
  }, [])
  return isMobile
}

/**
 * Non-hook version for use outside React components.
 */
export function isMobileDevice(): boolean {
  return detectMobile()
}

function detectMobile(): boolean {
  if (typeof window === 'undefined') return false
  const ua = navigator.userAgent || ''
  const mobileUA = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(ua)
  const narrowScreen = window.innerWidth <= 768
  const hasTouch = 'ontouchstart' in window || navigator.maxTouchPoints > 0
  return mobileUA || (narrowScreen && hasTouch)
}
