import React, { memo, useState, useEffect, useMemo, useCallback } from 'react'
import type { FC, ReactNode } from 'react'
import { useAppDispatch } from '@/store'
import AsideMenu from '@/views/main/c-cpns/left-asider/c-cpns/index'
import { BookMarkWraaper } from './style'
import { setCurrentRegion, type IRBRegion } from '@/store/modules/rna_browser_settings'
import { favouriteManager } from '@rbrowser/main'
import { useRenderer } from '@/store/renderer-ref'

import { Box, Typography, Divider, Input } from '@mui/joy'
import List from '@mui/material/List'
import ListItemButton from '@mui/material/ListItemButton'
import ListItemText from '@mui/material/ListItemText'
import Tooltip from '@mui/material/Tooltip'
import IconButton from '@mui/material/IconButton'
import DeleteIcon from '@mui/icons-material/DeleteOutline'
import SearchIcon from '@mui/icons-material/Search'
import CloseIcon from '@mui/icons-material/Close'

interface Iprops {
  children?: ReactNode
}

/* ───── 工具函数 ───── */

/** region 字符串解析：支持两种格式 */
const COORD_RE = /^(chr\w+):(\d+)-(\d+)$/i
// 支持 name:offset 和 name:offset:trans_type 两种格式
const TRANSCRIPT_RE = /^(.+?):(\d+)(?::(.+))?$/

interface ParsedRegion {
  raw: string
  displayName: string
  secondary: string
  isCoord: boolean
  transType?: string
  /** 用于导航的 IRBRegion */
  rbRegion: IRBRegion
}

function parseRegionString(region: string): ParsedRegion {
  // 尝试匹配坐标格式 chr1:100-200
  const coordMatch = region.match(COORD_RE)
  if (coordMatch) {
    const chr = coordMatch[1]
    const start = parseInt(coordMatch[2], 10)
    const end = parseInt(coordMatch[3], 10)
    return {
      raw: region,
      displayName: region,
      secondary: `${(end - start).toLocaleString()} bp`,
      isCoord: true,
      rbRegion: { chr, start, end }
    }
  }

  // 尝试匹配 transcript:offset 或 transcript:offset:trans_type
  const transMatch = region.match(TRANSCRIPT_RE)
  if (transMatch) {
    const name = transMatch[1]
    const offset = parseInt(transMatch[2], 10)
    const transType = transMatch[3] || undefined
    return {
      raw: region,
      displayName: name,
      secondary: `±${offset.toLocaleString()} bp`,
      isCoord: false,
      transType,
      rbRegion: { chr: '', start: 0, end: 0, trans_name: name, offset, level: 'RNA' }
    }
  }

  // 纯文本回退：当作 transcript name
  return {
    raw: region,
    displayName: region,
    secondary: '',
    isCoord: false,
    rbRegion: { chr: '', start: 0, end: 0, trans_name: region }
  }
}

/** TransType 徽标（参考 Search 面板的 TransTypeBadge） */
const TransTypeBadge: React.FC<{ transType?: string; isCoord?: boolean; size?: number }> = ({
  transType,
  isCoord,
  size = 18
}) => {
  // 使用 R/D/C 徽标
  const MODE_BADGE: Record<string, { color: string; char: string }> = {
    rna: { color: '#00b894', char: 'R' },
    dna: { color: '#3867d6', char: 'D' },
    cds: { color: '#f58518', char: 'C' }
  }
  let mode = 'rna'
  if (isCoord) mode = 'dna'
  const badge = MODE_BADGE[mode] ?? MODE_BADGE.rna
  return (
    <Box
      component='span'
      sx={{
        width: size,
        height: size,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center',
        borderRadius: '3px',
        backgroundColor: badge.color,
        color: '#fff',
        fontSize: 10,
        fontWeight: 700,
        lineHeight: 1,
        flex: '0 0 auto',
        userSelect: 'none',
        mr: 0.75
      }}>
      {badge.char}
    </Box>
  )
}

/* ───── 组件 ───── */

const BookMark: FC<Iprops> = () => {
  const dispatch = useAppDispatch()

  // 获取 renderer 以检测当前模式
  const renderer = useRenderer() as any

  /** 从 favouriteManager 读取收藏列表，并通过 on() 订阅变化 */
  const [favourites, setFavourites] = useState<string[]>(() => favouriteManager.getAll())

  useEffect(() => {
    // 初始同步
    setFavourites(favouriteManager.getAll())
    // 订阅增删变化
    const unsub = favouriteManager.on(() => {
      setFavourites(favouriteManager.getAll())
    })
    return unsub
  }, [])

  /** 点击条目 → 导航（根据当前 renderer 模式决定 RNA / CDS） */
  const handleClick = useCallback(
    (parsed: ParsedRegion) => {
      const region = { ...parsed.rbRegion }
      // 如果是 transcript 格式且 renderer 处于 CDS 模式，则以 CDS 方式导航
      if (!parsed.isCoord && renderer) {
        if (renderer.isCdsMode) {
          region.level = 'CDS'
        } else {
          region.level = 'RNA'
        }
      }
      dispatch(setCurrentRegion(region))
    },
    [dispatch, renderer]
  )

  /** 删除条目 */
  const handleDelete = useCallback((region: string) => {
    favouriteManager.remove(region)
  }, [])

  /** 搜索框状态 + 去抖 */
  const [query, setQuery] = useState('')
  const [debounced, setDebounced] = useState(query)
  useEffect(() => {
    const t = setTimeout(() => setDebounced(query.trim()), 180)
    return () => clearTimeout(t)
  }, [query])

  /** 解析 + 过滤（最新收藏排在最前面） */
  const items = useMemo(() => {
    // reverse() 使最新收藏排在最前
    const parsed = [...favourites].reverse().map(parseRegionString)
    if (!debounced) return parsed
    const q = debounced.toLowerCase()
    return parsed.filter(
      (p) =>
        p.displayName.toLowerCase().includes(q) ||
        p.raw.toLowerCase().includes(q) ||
        p.secondary.toLowerCase().includes(q)
    )
  }, [favourites, debounced])

  return (
    <BookMarkWraaper>
      <AsideMenu name='Favorites' />

      <div className='content'>
        {/* 顶部搜索框（吸顶） */}
        <Box
          sx={{
            position: 'sticky',
            top: 0,
            zIndex: 3,
            bgcolor: 'background.body',
            borderBottom: '1px solid',
            borderColor: 'divider',
            p: '3px 8px',
            height: 38,
            display: 'flex',
            alignItems: 'center',
            boxShadow: 'none'
          }}>
          <Input
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder='Search favourites…'
            size='sm'
            startDecorator={<SearchIcon fontSize='small' />}
            sx={{
              flex: 1,
              p: '3px',
              '--Input-focusedThickness': '0px',
              '--variant-borderWidth': '0px',
              border: 'none',
              boxShadow: 'none',
              backgroundColor: 'transparent',
              '&::before': { display: 'none' }
            }}
            endDecorator={
              query ? (
                <IconButton size='small' onClick={() => setQuery('')} sx={{ p: 0.25 }}>
                  <CloseIcon fontSize='small' />
                </IconButton>
              ) : null
            }
            slotProps={{ input: { 'aria-label': 'Search favourites' } }}
          />
        </Box>

        {/* 收藏列表 */}
        {items.length > 0 ? (
          <List dense disablePadding>
            {items.map((p, i) => (
              <React.Fragment key={p.raw}>
                <ListItemButton dense onClick={() => handleClick(p)} sx={{ pr: '5px', gap: 0, alignItems: 'center' }}>
                  {/* 类型徽标 */}
                  <TransTypeBadge transType={p.transType} isCoord={p.isCoord} size={16} />

                  <ListItemText
                    primary={p.displayName}
                    secondary={p.secondary}
                    primaryTypographyProps={{ fontSize: 12, noWrap: true }}
                    secondaryTypographyProps={{ fontSize: 10, color: 'text.disabled' }}
                    sx={{
                      pl: '5px',
                      m: 0,
                      whiteSpace: 'nowrap',
                      overflow: 'hidden',
                      textOverflow: 'ellipsis'
                    }}
                  />

                  {/* 右侧删除按钮（悬浮可见） */}
                  <Box
                    sx={{
                      ml: 'auto',
                      display: 'flex',
                      alignItems: 'center',
                      backgroundColor: 'transparent',
                      gap: 0,
                      opacity: 0,
                      transition: 'opacity 0.2s',
                      '.MuiListItemButton-root:hover &': { opacity: 1 }
                    }}>
                    <IconButton
                      size='small'
                      onClick={(e) => {
                        e.stopPropagation()
                        handleDelete(p.raw)
                      }}
                      sx={{
                        color: 'grey.500',
                        p: 0.25,
                        fontSize: 18
                      }}>
                      <DeleteIcon fontSize='inherit' />
                    </IconButton>
                  </Box>
                </ListItemButton>
                {i < items.length - 1 && <Divider sx={{ my: 0 }} />}
              </React.Fragment>
            ))}
          </List>
        ) : null}

        {/* 空态 */}
        {favourites.length === 0 && (
          <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
            No favourites <br /> Use the star button in RBrowser to add favourites
          </Typography>
        )}
        {favourites.length > 0 && items.length === 0 && (
          <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
            No matches <br /> Try another keyword.
          </Typography>
        )}
      </div>
    </BookMarkWraaper>
  )
}

export default memo(BookMark)
