/**
 * Selection 面板 - 使用 renderer.highlightManager 管理高亮区域
 *
 * 功能：
 * - 添加新高亮区域 (setRegion)
 * - 清除所有高亮 (clear)
 * - 删除单个高亮 (removeRegion)
 * - 切换 DNA/RNA/CDS 模式展示
 * - 列出所有高亮区域，支持编辑 color / start / end
 * - 鼠标悬浮显示删除按钮（参考 Favorites 代码）
 */
import React, { memo, useEffect, useState, useCallback } from 'react'
import type { FC, ReactNode } from 'react'
import AsideMenu from '../../aside-menu'
import { RegionWrapper } from './style'
import { useRenderer } from '@/store/renderer-ref'

import { Stack, Divider, Typography, Box, Input } from '@mui/joy'
import List from '@mui/material/List'
import ListItemButton from '@mui/material/ListItemButton'
import MuiIconButton from '@mui/material/IconButton'
import Tooltip from '@mui/material/Tooltip'
import DeleteIcon from '@mui/icons-material/DeleteOutline'
import RefreshIcon from '@mui/icons-material/Refresh'
import AddIcon from '@mui/icons-material/Add'
import VisibilityOutlinedIcon from '@mui/icons-material/VisibilityOutlined'
import VisibilityOffOutlinedIcon from '@mui/icons-material/VisibilityOffOutlined'

interface Iprops {
  children?: ReactNode
}

// ======== 常量 ========
const BADGE_SIZE = 16
const POLL_MS = 500

// ======== 单字符徽标（R/C/D） ========
const MODE_META: Record<string, { color: string; char: string }> = {
  rna: { color: '#00b894', char: 'R' },
  cds: { color: '#f58518', char: 'C' },
  dna: { color: '#3867d6', char: 'D' },
  other: { color: '#9E9E9E', char: '?' }
}

// ======== 颜色调色板 ========
const COLOR_PALETTE = [
  '#ff3b30',
  '#ff6259',
  '#ff2d55',
  '#e15759',
  '#c0392b',
  '#a93226',
  '#ff9500',
  '#ff6348',
  '#f39c12',
  '#fdcb6e',
  '#f1c40f',
  '#ffeaa7',
  '#34c759',
  '#2ed573',
  '#27ae60',
  '#00b894',
  '#1abc9c',
  '#55efc4',
  '#007aff',
  '#5856d6',
  '#0984e3',
  '#74b9ff',
  '#00cec9',
  '#81ecec',
  '#af52de',
  '#6c5ce7',
  '#a29bfe',
  '#fd79a8',
  '#e84393',
  '#d63031',
  '#1d1d1f',
  '#2d3436',
  '#636e72',
  '#747d8c',
  '#b2bec3',
  '#dfe6e9',
  '#f5f5f7',
  '#ffffff',
  '#fafafa',
  '#ecf0f1',
  '#bdc3c7',
  '#95a5a6'
]

const OneCharBadge: React.FC<{ mode?: string; size?: number }> = ({ mode, size = BADGE_SIZE }) => {
  const key = (mode || 'other').toLowerCase()
  const meta = MODE_META[key] ?? MODE_META.other
  return (
    <Box
      component='span'
      sx={{
        width: size,
        height: size,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center',
        borderRadius: '3px',
        backgroundColor: meta.color,
        color: '#fff',
        fontSize: size <= 16 ? 10 : 11,
        fontWeight: 700,
        lineHeight: 1,
        flex: '0 0 auto',
        userSelect: 'none'
      }}>
      {meta.char}
    </Box>
  )
}

// ======== 默认颜色轮转 ========
const DEFAULT_COLORS = ['#ffc107', '#ff5722', '#4caf50', '#2196f3', '#9c27b0', '#e91e63', '#00bcd4', '#ff9800']
let colorIndex = 0
function nextColor(): string {
  const c = DEFAULT_COLORS[colorIndex % DEFAULT_COLORS.length]
  colorIndex++
  return c
}

// ======== 输入框样式 ========
const inputStyle = {
  height: '24px',
  minHeight: '24px',
  fontSize: '12px',
  border: 'none',
  textAlign: 'end' as const,
  '--Input-radius': '0px',
  p: '2px 4px',
  lineHeight: '24px',
  boxSizing: 'border-box' as const,
  '&::before': {
    border: '1px solid var(--Input-focusedHighlight)',
    transform: 'scaleX(0)',
    left: 0,
    right: 0,
    bottom: '-1px',
    top: 'unset',
    transition: 'transform .15s cubic-bezier(0.1,0.9,0.2,1)',
    borderRadius: 0
  },
  '&:focus-within::before': {
    transform: 'scaleX(1)'
  }
}

// ======== 高亮区域接口 ========
interface HighlightItem {
  name: string
  start: number
  end: number
  color: string
}

/** getRegionList() 返回的单条目 */
interface RegionListEntry {
  chr: string
  start: number
  end: number
  strand: string
  trans_id?: string
  trans_name?: string
  gene_id?: string
  gene_name?: string
  tss?: number
}

/** getRegionList() 返回的多模式结构 */
interface RegionListResult {
  DNA: RegionListEntry[]
  RNA: RegionListEntry[]
  CDS: RegionListEntry[]
}

type RegionMode = 'dna' | 'rna' | 'cds'

const Region: FC<Iprops> = () => {
  /** 原始 HighlightManager.regions（用于编辑、删除等操作） */
  const [regions, setRegions] = useState<HighlightItem[]>([])
  /** renderer.getRegionList() 的多模式坐标快照 */
  const [regionList, setRegionList] = useState<RegionListResult | null>(null)
  const [regionMode, setRegionMode] = useState<RegionMode>('dna')
  const [highlightVisible, setHighlightVisible] = useState<boolean>(true)

  // 从 singleton 获取 renderer 实例
  const renderer = useRenderer() as any

  // 获取 highlightManager
  const getHM = useCallback(() => {
    return renderer?.highlightManager ?? null
  }, [renderer])

  /** 当前模式的显示坐标（按 index 与 regions 一一对应） */
  const displayEntries: RegionListEntry[] = React.useMemo(() => {
    if (!regionList) return []
    const key = regionMode.toUpperCase() as keyof RegionListResult
    return regionList[key] ?? []
  }, [regionList, regionMode])

  /** 定时轮询 highlightManager.regions + getRegionList() */
  useEffect(() => {
    const sync = () => {
      const hm = getHM()
      if (!hm) return
      const current = hm.regions as HighlightItem[]
      setRegions([...current])
      if (renderer && typeof renderer.isHighlightVisible === 'function') {
        setHighlightVisible(renderer.isHighlightVisible())
      }
      // 多模式坐标
      if (renderer && typeof renderer.getRegionList === 'function') {
        try {
          setRegionList(renderer.getRegionList())
        } catch {
          /* ignore */
        }
      }
    }
    sync()
    const timer = setInterval(sync, POLL_MS)
    return () => clearInterval(timer)
  }, [getHM, renderer])

  /** 同步 renderer 当前模式 */
  useEffect(() => {
    if (!renderer) return
    const syncMode = () => {
      if (renderer.isCdsMode) setRegionMode('cds')
      else if (renderer.isRnaMode) setRegionMode('rna')
      else setRegionMode('dna')
    }
    syncMode()
    const timer = setInterval(syncMode, POLL_MS)
    return () => clearInterval(timer)
  }, [renderer])

  /** 添加新高亮区域 */
  const handleAdd = useCallback(() => {
    const hm = getHM()
    if (!hm || !renderer) return

    const name = `Region-${Date.now()}`
    let start = 1000
    let end = 2000
    try {
      if (renderer.viewDomain) {
        const domain = renderer.viewDomain
        const mid = Math.floor((domain.start + domain.end) / 2)
        const span = Math.max(1, Math.floor((domain.end - domain.start) / 10))
        start = mid - span
        end = mid + span
      }
    } catch {
      // fallback
    }

    const color = nextColor()
    hm.setRegion(name, start, end, color)
    renderer.forceRedraw()
    setRegions([...hm.regions])
  }, [getHM, renderer])

  /** 删除指定高亮区域 */
  const handleDelete = useCallback(
    (name: string) => {
      const hm = getHM()
      if (!hm || !renderer) return
      hm.removeRegion(name)
      renderer.forceRedraw()
      setRegions([...hm.regions])
    },
    [getHM, renderer]
  )

  /** 清除所有高亮 */
  const handleClearAll = useCallback(() => {
    const hm = getHM()
    if (!hm || !renderer) return
    hm.clear()
    renderer.forceRedraw()
    setRegions([])
  }, [getHM, renderer])

  /** 更新区域字段（start / end / color） */
  const handleUpdate = useCallback(
    (name: string, field: 'start' | 'end' | 'color', value: number | string) => {
      const hm = getHM()
      if (!hm || !renderer) return
      const existing = (hm.regions as HighlightItem[]).find((r) => r.name === name)
      if (!existing) return

      const newStart = field === 'start' ? (value as number) : existing.start
      const newEnd = field === 'end' ? (value as number) : existing.end
      const newColor = field === 'color' ? (value as string) : existing.color

      hm.setRegion(name, newStart, newEnd, newColor)
      renderer.forceRedraw()
      setRegions([...hm.regions])
    },
    [getHM, renderer]
  )

  /** 切换高亮可见性 */
  const handleToggleVisibility = useCallback(() => {
    if (!renderer) return
    const next = !highlightVisible
    renderer.setHighlightVisible(next)
    renderer.forceRedraw()
    setHighlightVisible(next)
  }, [renderer, highlightVisible])

  /** 模式显示文本 */
  const modeLabel = regionMode === 'cds' ? 'CDS Mode' : regionMode === 'rna' ? 'RNA Mode' : 'DNA Mode'

  return (
    <RegionWrapper style={{ display: 'flex', flexDirection: 'column' }}>
      <AsideMenu name='Selection' />

      {/* 顶部控制条 */}
      <Stack
        direction='row'
        spacing={0.5}
        sx={{
          p: '3px',
          minWidth: 120,
          width: '100%',
          padding: '6px  15px 4px 15px',
          whiteSpace: 'nowrap',
          alignItems: 'center'
        }}>
        {/* 模式文本显示（只读） */}
        <Typography
          sx={{
            flex: 1,
            fontSize: 13,
            fontWeight: 600,
            color: 'neutral.700',
            userSelect: 'none',
            pl: 0.5
          }}>
          {modeLabel}
        </Typography>

        <Tooltip title='Add highlight region' placement='top'>
          <MuiIconButton size='small' onClick={handleAdd} sx={{ p: 0.5 }}>
            <AddIcon sx={{ fontSize: 18, color: '#3867d6' }} />
          </MuiIconButton>
        </Tooltip>

        <Tooltip title={highlightVisible ? 'Hide highlights' : 'Show highlights'} placement='top'>
          <MuiIconButton size='small' onClick={handleToggleVisibility} sx={{ p: 0.5 }}>
            {highlightVisible ? (
              <VisibilityOutlinedIcon sx={{ fontSize: 18, color: '#3867d6' }} />
            ) : (
              <VisibilityOffOutlinedIcon sx={{ fontSize: 18 }} />
            )}
          </MuiIconButton>
        </Tooltip>

        <Tooltip title='Clear all highlights' placement='top'>
          <MuiIconButton size='small' onClick={handleClearAll} sx={{ p: 0.5 }}>
            <RefreshIcon sx={{ fontSize: 18, color: '#3867d6' }} />
          </MuiIconButton>
        </Tooltip>
      </Stack>

      <Divider sx={{ my: 0.2, height: '0.5px' }} />

      {/* 标题 + 计数 */}
      <Box
        sx={{
          px: 1,
          py: 0.25,
          display: 'flex',
          alignItems: 'center',
          gap: 0.5,
          minHeight: 26,
          height: 26
        }}>
        <Typography
          noWrap
          sx={{
            px: 0.5,
            py: 0.5,
            fontSize: 12,
            color: 'neutral.500',
            textTransform: 'uppercase',
            letterSpacing: 0.3,
            userSelect: 'none',
            flex: 1,
            overflow: 'hidden',
            textOverflow: 'ellipsis'
          }}>
          Highlights ({regionMode.toUpperCase()})
        </Typography>
        <Typography
          component='span'
          sx={{
            fontSize: 12,
            color: 'neutral.500',
            minWidth: 24,
            textAlign: 'right',
            ml: 0.5,
            flex: '0 0 auto'
          }}>
          {regions.length}
        </Typography>
      </Box>

      {/* 高亮列表 */}
      <Stack spacing={0} sx={{ width: '100%', flex: 1, overflow: 'hidden' }}>
        {regions.length > 0 ? (
          <Box sx={{ height: '100%', overflowY: 'auto' }}>
            <List dense disablePadding>
              {regions.map((region, idx) => {
                // 使用 getRegionList() 获取当前模式下的坐标
                const entry = displayEntries[idx]
                const displayStart = entry ? entry.start : region.start
                const displayEnd = entry ? entry.end : region.end
                const displayChr = entry?.chr ?? ''
                return (
                  <React.Fragment key={region.name}>
                    <ListItemButton
                      dense
                      sx={{
                        px: '4px',
                        py: '2px',
                        gap: '4px',
                        alignItems: 'center',
                        minHeight: 28,
                        '&:hover .hover-reveal': { opacity: 1, width: 'auto', overflow: 'visible' }
                      }}>
                      {/* 颜色 picker（点击弹出调色板） */}
                      <Box
                        onClick={(e) => {
                          e.stopPropagation()
                          const trigger = e.currentTarget as HTMLElement
                          // 移除已有弹窗
                          const old = document.getElementById('__region_color_popup__')
                          if (old) old.remove()
                          // 创建弹窗
                          const popup = document.createElement('div')
                          popup.id = '__region_color_popup__'
                          Object.assign(popup.style, {
                            position: 'fixed',
                            zIndex: '300000',
                            background: '#fff',
                            border: '1px solid #d2d2d7',
                            borderRadius: '10px',
                            boxShadow: '0 8px 30px rgba(0,0,0,0.18)',
                            padding: '10px',
                            display: 'grid',
                            gridTemplateColumns: 'repeat(6, 28px)',
                            gap: '6px',
                            opacity: '0',
                            transform: 'scale(0.92)',
                            transition: 'opacity 0.2s, transform 0.2s'
                          })
                          COLOR_PALETTE.forEach((c) => {
                            const dot = document.createElement('div')
                            Object.assign(dot.style, {
                              width: '28px',
                              height: '28px',
                              borderRadius: '6px',
                              background: c,
                              cursor: 'pointer',
                              border: ['#ffffff', '#fafafa', '#f5f5f7', '#ecf0f1'].includes(c)
                                ? '1.5px solid #d2d2d7'
                                : '1.5px solid transparent',
                              transition: 'transform 0.2s'
                            })
                            dot.addEventListener('mouseenter', () => {
                              dot.style.transform = 'scale(1.15)'
                              dot.style.boxShadow = '0 2px 8px rgba(0,0,0,0.2)'
                            })
                            dot.addEventListener('mouseleave', () => {
                              dot.style.transform = ''
                              dot.style.boxShadow = ''
                            })
                            dot.addEventListener('click', (ev) => {
                              ev.stopPropagation()
                              handleUpdate(region.name, 'color', c)
                              dismiss()
                            })
                            popup.appendChild(dot)
                          })
                          const rect = trigger.getBoundingClientRect()
                          document.body.appendChild(popup)
                          let top = rect.bottom + 6
                          let left = rect.left
                          if (top + popup.offsetHeight > window.innerHeight - 10)
                            top = rect.top - popup.offsetHeight - 6
                          if (left + popup.offsetWidth > window.innerWidth - 10)
                            left = window.innerWidth - popup.offsetWidth - 10
                          if (left < 10) left = 10
                          popup.style.top = `${top}px`
                          popup.style.left = `${left}px`
                          requestAnimationFrame(() => {
                            popup.style.opacity = '1'
                            popup.style.transform = 'scale(1)'
                          })
                          const dismiss = () => {
                            popup.style.opacity = '0'
                            popup.style.transform = 'scale(0.92)'
                            setTimeout(() => popup.remove(), 200)
                            document.removeEventListener('mousedown', onOutside)
                            document.removeEventListener('keydown', onEsc)
                          }
                          const onOutside = (ev: MouseEvent) => {
                            if (!popup.contains(ev.target as Node)) dismiss()
                          }
                          const onEsc = (ev: KeyboardEvent) => {
                            if (ev.key === 'Escape') dismiss()
                          }
                          setTimeout(() => {
                            document.addEventListener('mousedown', onOutside)
                            document.addEventListener('keydown', onEsc)
                          }, 0)
                        }}
                        sx={{
                          width: 16,
                          height: 16,
                          flex: '0 0 auto',
                          cursor: 'pointer',
                          borderRadius: '3px',
                          backgroundColor: region.color || '#ffc107',
                          border: '1px solid rgba(0,0,0,0.15)'
                        }}
                      />

                      {/* 模式徽标 */}
                      <OneCharBadge mode={regionMode} />

                      {/* 坐标显示 — 根据模式显示不同坐标系 */}
                      <Box sx={{ flex: 1, display: 'flex', alignItems: 'center', gap: '2px', minWidth: 0 }}>
                        {displayChr && regionMode === 'dna' && (
                          <Typography
                            noWrap
                            sx={{ fontSize: 10, color: 'neutral.500', flex: '0 0 auto', maxWidth: 60 }}>
                            {displayChr}:
                          </Typography>
                        )}
                        <Input
                          sx={{ ...inputStyle, flex: 1, minWidth: 40 }}
                          value={displayStart}
                          type='number'
                          onChange={(e) => {
                            const v = parseInt(e.target.value)
                            if (!isNaN(v)) handleUpdate(region.name, 'start', v)
                          }}
                          onClick={(e) => e.stopPropagation()}
                        />
                        <Typography
                          sx={{ fontSize: 10, color: 'neutral.400', px: '1px', userSelect: 'none', flex: '0 0 auto' }}>
                          →
                        </Typography>
                        <Input
                          sx={{ ...inputStyle, flex: 1, minWidth: 40 }}
                          value={displayEnd}
                          type='number'
                          onChange={(e) => {
                            const v = parseInt(e.target.value)
                            if (!isNaN(v)) handleUpdate(region.name, 'end', v)
                          }}
                          onClick={(e) => e.stopPropagation()}
                        />
                      </Box>

                      {/* 长度 + 删除按钮：仅悬浮可见，不占宽度 */}
                      <Box
                        className='hover-reveal'
                        sx={{
                          display: 'flex',
                          alignItems: 'center',
                          gap: '2px',
                          opacity: 0,
                          width: 0,
                          overflow: 'hidden',
                          transition: 'opacity 0.2s',
                          flex: '0 0 auto',
                          whiteSpace: 'nowrap'
                        }}>
                        <Typography sx={{ fontSize: 10, color: 'neutral.500', minWidth: 32, textAlign: 'right' }}>
                          {(displayEnd - displayStart + 1).toLocaleString()}
                        </Typography>
                        <MuiIconButton
                          size='small'
                          onClick={(e) => {
                            e.stopPropagation()
                            handleDelete(region.name)
                          }}
                          sx={{ color: 'grey.500', p: 0.25, fontSize: 16 }}>
                          <DeleteIcon fontSize='inherit' />
                        </MuiIconButton>
                      </Box>
                    </ListItemButton>

                    {idx < regions.length - 1 && <Divider sx={{ my: 0 }} />}
                  </React.Fragment>
                )
              })}
            </List>
          </Box>
        ) : (
          <Typography sx={{ p: '10px 5px', color: '#707070', fontSize: 14, textAlign: 'center' }}>
            No highlights
            <br />
            Click the <strong>+</strong> button to add a highlight region.
          </Typography>
        )}
      </Stack>
    </RegionWrapper>
  )
}

export default memo(Region)
